type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object") {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type FlatRecord = Record<string, unknown>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function accumulateKeys(
  node: Record<string, unknown>,
  prefix: string,
  ancestorRefs: WeakSet<object>,
  accumulator: FlatRecord
): void {
  const ownKeys = Object.keys(node);

  if (ownKeys.length === 0) {
    if (prefix !== "") {
      accumulator[prefix] = node;
    }
    return;
  }

  for (const key of ownKeys) {
    const dotPath = prefix === "" ? key : `${prefix}.${key}`;
    const value = node[key];

    if (isPlainObject(value)) {
      if (ancestorRefs.has(value)) {
        accumulator[dotPath] = "[Circular]";
        continue;
      }
      const nextAncestors = new WeakSet(ancestorRefs);
      nextAncestors.add(value);
      accumulateKeys(value, dotPath, nextAncestors, accumulator);
    } else {
      accumulator[dotPath] = value;
    }
  }
}

export default function flattenObject(input: unknown): FlatRecord {
  if (!isPlainObject(input)) {
    return {};
  }

  const accumulator: FlatRecord = {};
  const rootAncestors = new WeakSet<object>([input]);
  accumulateKeys(input, "", rootAncestors, accumulator);
  return accumulator;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldBounds {
  readonly min: number;
  readonly max: number;
}

const FIELD_BOUNDS: Readonly<Record<CronField, FieldBounds>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
} as const;

const FIELD_ORDER: readonly CronField[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function parsedNonNegativeInteger(raw: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new TypeError(
      `Expected a non-negative integer but received "${raw}"`
    );
  }
  return parseInt(trimmed, 10);
}

function integerWithinBounds(raw: string, bounds: FieldBounds): number {
  const n = parsedNonNegativeInteger(raw);
  if (n < bounds.min || n > bounds.max) {
    throw new RangeError(
      `Value ${n} falls outside the allowed range [${bounds.min}, ${bounds.max}]`
    );
  }
  return n;
}

function integerSequence(from: number, to: number): number[] {
  if (from > to) {
    throw new RangeError(
      `Range start ${from} must not exceed range end ${to}`
    );
  }
  const result: number[] = [];
  for (let i = from; i <= to; i++) {
    result.push(i);
  }
  return result;
}

function steppedSequence(from: number, to: number, step: number): number[] {
  if (step <= 0) {
    throw new RangeError(`Step value ${step} must be a positive integer`);
  }
  if (from > to) {
    throw new RangeError(
      `Stepped sequence start ${from} must not exceed end ${to}`
    );
  }
  const result: number[] = [];
  for (let i = from; i <= to; i += step) {
    result.push(i);
  }
  return result;
}

function expandedStepToken(
  base: string,
  stepStr: string,
  bounds: FieldBounds
): number[] {
  const step = parsedNonNegativeInteger(stepStr);
  if (step === 0) {
    throw new RangeError(`Step value must be a positive integer, got 0`);
  }

  if (base === "*") {
    return steppedSequence(bounds.min, bounds.max, step);
  }

  const dashIndex = base.indexOf("-");
  if (dashIndex !== -1) {
    const rangeStart = integerWithinBounds(base.slice(0, dashIndex), bounds);
    const rangeEnd   = integerWithinBounds(base.slice(dashIndex + 1), bounds);
    return steppedSequence(rangeStart, rangeEnd, step);
  }

  const start = integerWithinBounds(base, bounds);
  return steppedSequence(start, bounds.max, step);
}

function expandedToken(token: string, bounds: FieldBounds): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty token in cron field expression`);
  }

  const slashIndex = trimmed.indexOf("/");
  if (slashIndex !== -1) {
    const base    = trimmed.slice(0, slashIndex);
    const stepStr = trimmed.slice(slashIndex + 1);
    if (base === "" || stepStr === "") {
      throw new SyntaxError(
        `Malformed step expression "${trimmed}" — expected base/step`
      );
    }
    return expandedStepToken(base, stepStr, bounds);
  }

  if (trimmed === "*") {
    return integerSequence(bounds.min, bounds.max);
  }

  const dashIndex = trimmed.indexOf("-");
  if (dashIndex !== -1) {
    if (dashIndex === 0 || dashIndex === trimmed.length - 1) {
      throw new SyntaxError(
        `Malformed range expression "${trimmed}" — dash at invalid position`
      );
    }
    const rangeStart = integerWithinBounds(trimmed.slice(0, dashIndex), bounds);
    const rangeEnd   = integerWithinBounds(trimmed.slice(dashIndex + 1), bounds);
    return integerSequence(rangeStart, rangeEnd);
  }

  return [integerWithinBounds(trimmed, bounds)];
}

function expandedField(fieldStr: string, bounds: FieldBounds): number[] {
  if (fieldStr.trim() === "") {
    throw new SyntaxError(`Cron field expression cannot be empty`);
  }

  const tokens = fieldStr.split(",");

  if (tokens.some(t => t.trim() === "")) {
    throw new SyntaxError(
      `Cron field "${fieldStr}" contains an empty token from a stray comma`
    );
  }

  const allValues = tokens.flatMap(token => expandedToken(token, bounds));
  return [...new Set(allValues)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron requires a string argument, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Cron expression must not be empty`);
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression requires exactly 5 space-separated fields, got ${fields.length}`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const fieldStr  = fields[i];
    const bounds    = FIELD_BOUNDS[fieldName];

    try {
      result[fieldName] = expandedField(fieldStr, bounds);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new (err instanceof TypeError ? TypeError : err instanceof RangeError ? RangeError : SyntaxError)(
        `Invalid cron field "${fieldName}" (position ${i + 1}, value "${fieldStr}"): ${message}`
      );
    }
  }

  return result;
}

type CronResult = { minute: number[]; hour: number[]; dayOfMonth: number[]; month: number[]; dayOfWeek: number[] };

const RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59], hour: [0, 23], dayOfMonth: [1, 31], month: [1, 12], dayOfWeek: [0, 6],
};

function expand(field: string, min: number, max: number): number[] {
  const all = (): number[] => Array.from({ length: max - min + 1 }, (_, i) => i + min);

  if (field === "*") return all();

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (!step || step < 1 || step > max - min) throw new Error(`Invalid step: "${field}"`);
    return all().filter((n) => (n - min) % step === 0);
  }

  if (field.includes(",")) {
    const vals = [...new Set(field.split(",").flatMap((f) => expand(f, min, max)))];
    return vals.sort((a, b) => a - b);
  }

  if (field.includes("-")) {
    const [a, b] = field.split("-").map(Number);
    if (isNaN(a) || isNaN(b) || a < min || b > max || a > b) throw new Error(`Invalid range: "${field}"`);
    return Array.from({ length: b - a + 1 }, (_, i) => i + a);
  }

  const n = parseInt(field, 10);
  if (isNaN(n) || n < min || n > max) throw new Error(`Invalid value: "${field}" (expected ${min}–${max})`);
  return [n];
}

export default function parseCron(expr: string): CronResult {
  const parts = expr.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);
  const keys = Object.keys(RANGES) as (keyof CronResult)[];
  return Object.fromEntries(
    keys.map((k, i) => [k, expand(parts[i], RANGES[k][0], RANGES[k][1])])
  ) as CronResult;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: string;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  }, // 7 accepted as Sunday alias
] as const satisfies FieldConfig[];

const INTEGER_RE = /^\d+$/;

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] in field "${context}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!INTEGER_RE.test(trimmed)) {
    throw new SyntaxError(`Expected integer but got "${trimmed}" in field "${context}"`);
  }
  return Number(trimmed);
}

function expandRange(start: number, end: number, step: number): number[] {
  if (start > end) {
    throw new RangeError(`Range start (${start}) must be ≤ range end (${end})`);
  }
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step}`);
  }
  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { name, min, max } = config;
  const trimmed = segment.trim();

  if (trimmed.length === 0) {
    throw new SyntaxError(`Empty segment encountered in field "${name}"`);
  }

  // Step expression: <range-or-wildcard>/<step>
  const slashIndex = trimmed.indexOf("/");
  if (slashIndex !== -1) {
    const rangePart = trimmed.slice(0, slashIndex);
    const stepPart = trimmed.slice(slashIndex + 1);

    if (rangePart.length === 0 || stepPart.length === 0) {
      throw new SyntaxError(`Malformed step expression "${trimmed}" in field "${name}"`);
    }

    const step = parseInteger(stepPart, name);
    if (step === 0) {
      throw new RangeError(`Step value cannot be zero in field "${name}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      const dashIndex = rangePart.indexOf("-");
      rangeMin = parseInteger(rangePart.slice(0, dashIndex), name);
      rangeMax = parseInteger(rangePart.slice(dashIndex + 1), name);
      assertInRange(rangeMin, min, max, name);
      assertInRange(rangeMax, min, max, name);
    } else {
      // e.g. "5/15" — start from 5, step to max
      rangeMin = parseInteger(rangePart, name);
      assertInRange(rangeMin, min, max, name);
      rangeMax = max;
    }

    return expandRange(rangeMin, rangeMax, step);
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(min, max, 1);
  }

  // Range: <start>-<end>
  const dashIndex = trimmed.indexOf("-");
  if (dashIndex !== -1) {
    // Guard against a leading "-" being mistaken for a range
    if (dashIndex === 0) {
      throw new SyntaxError(`Unexpected leading dash in "${trimmed}" in field "${name}"`);
    }
    const startStr = trimmed.slice(0, dashIndex);
    const endStr   = trimmed.slice(dashIndex + 1);

    if (endStr.includes("-")) {
      throw new SyntaxError(`Multiple dashes in range "${trimmed}" in field "${name}"`);
    }

    const start = parseInteger(startStr, name);
    const end   = parseInteger(endStr,   name);
    assertInRange(start, min, max, name);
    assertInRange(end,   min, max, name);

    if (start > end) {
      throw new RangeError(
        `Range start (${start}) must not exceed range end (${end}) in field "${name}"`
      );
    }

    return expandRange(start, end, 1);
  }

  // Single integer
  const value = parseInteger(trimmed, name);
  assertInRange(value, min, max, name);
  return [value];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (field.includes(",")) {
    const seen = new Set<number>();
    for (const segment of field.split(",")) {
      for (const v of parseSegment(segment, config)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }
  return parseSegment(field, config);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,   FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw,    FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,  FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dowRaw,    FIELD_CONFIGS[4]),
  };
}

type FlattenedObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (typeof value !== "object" || value === null || Array.isArray(value)) {
    return false;
  }
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function dotPath(prefix: string, key: string): string {
  return prefix.length > 0 ? `${prefix}.${key}` : key;
}

function recurseIntoObject(
  input: Record<string, unknown>,
  prefix: string,
  accumulator: FlattenedObject,
  ancestorChain: WeakSet<object>,
): void {
  for (const key of Object.keys(input)) {
    const path = dotPath(prefix, key);
    const value = input[key];

    if (!isPlainObject(value)) {
      accumulator[path] = value;
      continue;
    }

    if (ancestorChain.has(value)) {
      accumulator[path] = "[Circular]";
      continue;
    }

    const childKeys = Object.keys(value);

    if (childKeys.length === 0) {
      accumulator[path] = value;
      continue;
    }

    ancestorChain.add(value);
    recurseIntoObject(value, path, accumulator, ancestorChain);
    ancestorChain.delete(value);
  }
}

export default function flattenObject(input: Record<string, unknown>): FlattenedObject {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject requires a plain object; received ${input === null ? "null" : Array.isArray(input) ? "array" : typeof input}`,
    );
  }

  const accumulator: FlattenedObject = {};
  const ancestorChain = new WeakSet<object>([input]);

  recurseIntoObject(input, "", accumulator, ancestorChain);

  return accumulator;
}

type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: unknown };

function flattenObject(obj: NestedObject, prefix = ""): FlatObject {
  const result: FlatObject = {};

  for (const [key, value] of Object.entries(obj)) {
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
      Object.assign(result, flattenObject(value as NestedObject, flatKey));
    } else {
      result[flatKey] = value;
    }
  }

  return result;
}

export default flattenObject;

type NestedObject = { [key: string]: unknown };
type FlattenedObject = { [key: string]: unknown };

const isTraversablePlainObject = (value: unknown): value is NestedObject =>
  value !== null &&
  typeof value === "object" &&
  !Array.isArray(value) &&
  (Object.getPrototypeOf(value) === Object.prototype ||
    Object.getPrototypeOf(value) === null);

const flattenObjectInto = (
  obj: NestedObject,
  prefixSegments: readonly string[],
  ancestorSet: Set<object>,
  accumulator: FlattenedObject
): void => {
  // Cycle detection: if this exact object reference is already being traversed
  // up the call stack, treat it as a leaf to avoid infinite recursion.
  if (ancestorSet.has(obj)) {
    const cyclicKey = prefixSegments.join(".");
    accumulator[cyclicKey] = "[Circular]";
    return;
  }

  ancestorSet.add(obj);

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const segments = [...prefixSegments, key];

    if (isTraversablePlainObject(value)) {
      const ownKeys = Object.keys(value);

      // An empty nested object has no leaf values to emit.
      // Emitting nothing is the least surprising behavior:
      // there is no lossless flat representation of an empty branch.
      if (ownKeys.length > 0) {
        flattenObjectInto(value, segments, ancestorSet, accumulator);
      }
    } else {
      accumulator[segments.join(".")] = value;
    }
  }

  // Remove on exit so the same object reference may appear in sibling
  // branches without being misidentified as a cycle.
  ancestorSet.delete(obj);
};

const flattenObject = (input: unknown): FlattenedObject => {
  // Inputs that are not traversable plain objects have no meaningful
  // dot-notation decomposition; return empty rather than throw so callers
  // do not need to pre-screen.
  if (!isTraversablePlainObject(input)) {
    return {};
  }

  const accumulator: FlattenedObject = {};
  flattenObjectInto(input, [], new Set<object>(), accumulator);
  return accumulator;
};

export default flattenObject;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(token: string, min: number, max: number): number[] {
  // Wildcard
  if (token === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Step value: */step or start-end/step
  if (token.includes("/")) {
    const [rangePart, stepPart] = token.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value: ${stepPart}`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = clamp(s, min, max);
        end = clamp(e, min, max);
        if (start > end) throw new Error(`Invalid range: ${rangePart}`);
      } else {
        start = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    const results: number[] = [];
    for (let i = start; i <= end; i += step) {
      results.push(i);
    }
    return results;
  }

  // Comma-separated list
  if (token.includes(",")) {
    const values = token.split(",").flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Range: start-end
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new Error(`Invalid range: ${token}`);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single number
  const num = parseInt(token, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid cron field value: ${token}`);
  }
  return [clamp(num, min, max)];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${fields.length}`
    );
  }

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as Array<keyof CronResult>;
  const tokens = [minuteToken, hourToken, domToken, monthToken, dowToken];

  const result = {} as CronResult;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const { min, max } = FIELD_RANGES[name];
    try {
      result[name] = parseField(tokens[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid value for field "${name}" ("${tokens[i]}"): ${(err as Error).message}`
      );
    }
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function expandRange(min: number, max: number, step = 1): number[] {
  const values: number[] = [];
  for (let i = min; i <= max; i += step) {
    values.push(i);
  }
  return values;
}

function parseField(expr: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  const validate = (n: number): number => {
    if (n < min || n > max) {
      throw new RangeError(`Value ${n} out of range [${min}, ${max}] for field "${field}"`);
    }
    return n;
  };

  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (expr === "*") {
    return expandRange(min, max);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value in "${expr}" for field "${field}"`);
    }
    return expandRange(min, max, step);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value in "${expr}" for field "${field}"`);
    }
    if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map((s) => parseInt(s, 10));
      if (isNaN(lo) || isNaN(hi)) {
        throw new Error(`Invalid range in "${expr}" for field "${field}"`);
      }
      validate(lo);
      validate(hi);
      if (lo > hi) {
        throw new RangeError(`Range start ${lo} > end ${hi} for field "${field}"`);
      }
      return expandRange(lo, hi, step);
    }
    const start = parseInt(rangePart, 10);
    if (isNaN(start)) {
      throw new Error(`Invalid expression "${expr}" for field "${field}"`);
    }
    validate(start);
    return expandRange(start, max, step);
  }

  if (expr.includes("-")) {
    const [lo, hi] = expr.split("-").map((s) => parseInt(s, 10));
    if (isNaN(lo) || isNaN(hi)) {
      throw new Error(`Invalid range in "${expr}" for field "${field}"`);
    }
    validate(lo);
    validate(hi);
    if (lo > hi) {
      throw new RangeError(`Range start ${lo} > end ${hi} for field "${field}"`);
    }
    return expandRange(lo, hi);
  }

  const num = parseInt(expr, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid expression "${expr}" for field "${field}"`);
  }

  // Normalize dayOfWeek: treat 7 as 0 (both are Sunday)
  if (field === "dayOfWeek" && num === 7) {
    return [0];
  }

  return [validate(num)];
}

export default function parseCron(expression: string): ParsedCron {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: Record<string, Primitive> = {}
): Record<string, Primitive> {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }
  const keys = Object.keys(obj);
  if (keys.length === 0 && prefix) {
    result[prefix] = {} as unknown as Primitive;
    return result;
  }
  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;
    flattenObject(obj[key] as NestedObject, prefix ? `${prefix}.${key}` : key, result);
  }
  return result;
}

type CronFieldName = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldBounds {
  readonly min: number;
  readonly max: number;
}

const FIELD_BOUNDS: Readonly<Record<CronFieldName, FieldBounds>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: readonly CronFieldName[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function integerFromToken(raw: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Non-integer token: "${raw}"`);
  }
  const n = parseInt(raw, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer overflow in token: "${raw}"`);
  }
  return n;
}

function boundsEnforced(value: number, bounds: FieldBounds, context: string): number {
  if (value < bounds.min || value > bounds.max) {
    throw new Error(
      `Value ${value} out of bounds [${bounds.min}, ${bounds.max}] in "${context}"`
    );
  }
  return value;
}

function steppedSequence(
  start: number,
  end: number,
  step: number,
  bounds: FieldBounds,
  rawToken: string
): number[] {
  if (step <= 0) {
    throw new Error(`Step must be a positive integer, got ${step} in "${rawToken}"`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} exceeds end ${end} in "${rawToken}"`);
  }
  boundsEnforced(start, bounds, rawToken);
  boundsEnforced(end,   bounds, rawToken);

  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function atomicTokenExpansion(token: string, bounds: FieldBounds): number[] {
  const slashIndex = token.indexOf("/");

  if (slashIndex !== -1) {
    const left  = token.slice(0, slashIndex);
    const right = token.slice(slashIndex + 1);

    if (right === "") {
      throw new Error(`Missing step value in "${token}"`);
    }
    const step = integerFromToken(right);

    if (left === "*") {
      return steppedSequence(bounds.min, bounds.max, step, bounds, token);
    }

    const dashIndex = left.indexOf("-");
    if (dashIndex !== -1) {
      const start = boundsEnforced(integerFromToken(left.slice(0, dashIndex)), bounds, token);
      const end   = boundsEnforced(integerFromToken(left.slice(dashIndex + 1)), bounds, token);
      return steppedSequence(start, end, step, bounds, token);
    }

    const start = boundsEnforced(integerFromToken(left), bounds, token);
    return steppedSequence(start, bounds.max, step, bounds, token);
  }

  if (token === "*") {
    return steppedSequence(bounds.min, bounds.max, 1, bounds, token);
  }

  const dashIndex = token.indexOf("-");
  if (dashIndex !== -1) {
    if (dashIndex === 0 || dashIndex === token.length - 1) {
      throw new Error(`Malformed range in "${token}"`);
    }
    const start = boundsEnforced(integerFromToken(token.slice(0, dashIndex)), bounds, token);
    const end   = boundsEnforced(integerFromToken(token.slice(dashIndex + 1)), bounds, token);
    return steppedSequence(start, end, 1, bounds, token);
  }

  const single = integerFromToken(token);
  boundsEnforced(single, bounds, token);
  return [single];
}

function fieldToSortedValues(field: string, bounds: FieldBounds): number[] {
  if (field === "") {
    throw new Error("Empty cron field");
  }

  const parts = field.split(",");

  for (const part of parts) {
    if (part.trim() === "") {
      throw new Error(`Empty segment in comma-separated field: "${field}"`);
    }
  }

  const accumulated = new Set<number>();

  for (const part of parts) {
    for (const value of atomicTokenExpansion(part.trim(), bounds)) {
      accumulated.add(value);
    }
  }

  return Array.from(accumulated).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Expression must be a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const rawFields = trimmed.split(/\s+/);

  if (rawFields.length !== 5) {
    throw new Error(
      `Cron expression must contain exactly 5 fields, got ${rawFields.length}: "${trimmed}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = fieldToSortedValues(rawFields[i], FIELD_BOUNDS[fieldName]);
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

function assertInRange(value: number, field: CronField): void {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range for field "${field}" (expected ${min}-${max})`
    );
  }
}

function expandRange(start: number, end: number, step: number, field: CronField): number[] {
  if (start > end) {
    throw new RangeError(
      `Invalid range ${start}-${end} for field "${field}": start must be <= end`
    );
  }
  if (step < 1) {
    throw new RangeError(`Step value must be >= 1, got ${step}`);
  }
  assertInRange(start, field);
  assertInRange(end, field);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Step value: */n or range/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepPart}" in field "${field}"`);
    }
    if (rangePart === "*") {
      return expandRange(min, max, step, field);
    }
    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new SyntaxError(`Invalid range "${rangePart}" in field "${field}"`);
      }
      return expandRange(start, end, step, field);
    }
    const base = parseInt(rangePart, 10);
    if (isNaN(base)) {
      throw new SyntaxError(`Invalid step expression "${segment}" in field "${field}"`);
    }
    return expandRange(base, max, step, field);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max, 1, field);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    return expandRange(start, end, 1, field);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  assertInRange(value, field);
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`Empty expression for field "${field}"`);
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in field "${field}"`);
    }
    for (const v of parseSegment(trimmed, field)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

type FieldName = keyof typeof FIELD_RANGES;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function range(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseField(expr: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (expr.includes(",")) {
    return [...new Set(expr.split(",").flatMap(part => parseField(part.trim(), field)))].sort((a, b) => a - b);
  }

  if (expr === "*") {
    return range(min, max);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value in "${expr}" for field "${field}"`);
    return range(min, max, step);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value in "${expr}" for field "${field}"`);
    if (rangePart === "*") return range(min, max, step);
    const [start, end] = rangePart.split("-").map(n => parseInt(n, 10));
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in "${expr}" for field "${field}"`);
    if (start < min || end > max || start > end) throw new Error(`Range out of bounds in "${expr}" for field "${field}"`);
    return range(start, end, step);
  }

  if (expr.includes("-")) {
    const [start, end] = expr.split("-").map(n => parseInt(n, 10));
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range "${expr}" for field "${field}"`);
    if (start < min || end > max || start > end) throw new Error(`Range out of bounds in "${expr}" for field "${field}"`);
    return range(start, end);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid value "${expr}" for field "${field}"`);
  if (value < min || value > max) throw new Error(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  return [value];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function rangeArray(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) result.push(i);
  return result;
}

function dedup(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Step: */n or x-y/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value "${stepPart}" in field "${fieldName}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map(Number);
        if (isNaN(lo) || isNaN(hi)) {
          throw new SyntaxError(`Invalid range "${rangePart}" in field "${fieldName}"`);
        }
        assertInRange(lo, min, max, fieldName);
        assertInRange(hi, min, max, fieldName);
        if (lo > hi) throw new RangeError(`Range start ${lo} > end ${hi} in field "${fieldName}"`);
        rangeMin = lo;
        rangeMax = hi;
      } else {
        const start = parseInt(rangePart, 10);
        if (isNaN(start)) {
          throw new SyntaxError(`Invalid step base "${rangePart}" in field "${fieldName}"`);
        }
        assertInRange(start, min, max, fieldName);
        rangeMin = start;
      }
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) values.push(i);
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Range: x-y
  if (segment.includes("-")) {
    const [lo, hi] = segment.split("-").map(Number);
    if (isNaN(lo) || isNaN(hi)) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    assertInRange(lo, min, max, fieldName);
    assertInRange(hi, min, max, fieldName);
    if (lo > hi) throw new RangeError(`Range start ${lo} > end ${hi} in field "${fieldName}"`);
    return rangeArray(lo, hi);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(expression: string, fieldName: keyof CronFields): number[] {
  const { min, max } = FIELD_RANGES[fieldName];

  const parts = expression.split(",");
  if (parts.length === 0) {
    throw new SyntaxError(`Empty expression for field "${fieldName}"`);
  }

  const values = parts.flatMap((part) => parseSegment(part.trim(), min, max, fieldName));

  // Normalize dayOfWeek: treat 7 as 0 (both are Sunday)
  const normalized =
    fieldName === "dayOfWeek" ? values.map((v) => (v === 7 ? 0 : v)) : values;

  return dedup(normalized);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}. Format: "minute hour dayOfMonth month dayOfWeek"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

type Scalar = string | number | boolean | null | undefined | bigint | symbol;

function isPlainObject(val: unknown): val is Record<string, unknown> {
  if (val === null || typeof val !== "object") return false;
  const proto = Object.getPrototypeOf(val);
  return proto === Object.prototype || proto === null;
}

function flatten(
  obj: Record<string, unknown>,
  prefix: string,
  seen: WeakSet<object>,
  result: Record<string, Scalar | unknown[]>
): void {
  if (seen.has(obj)) return; // circular reference — skip silently
  seen.add(obj);

  const keys = Object.keys(obj); // own enumerable string keys only
  for (const key of keys) {
    const val = obj[key];
    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(val)) {
      const childKeys = Object.keys(val);
      if (childKeys.length === 0) {
        // Empty plain object — preserve as a leaf so callers know it existed
        (result as Record<string, unknown>)[fullKey] = val;
      } else {
        flatten(val, fullKey, seen, result);
      }
    } else {
      // Scalars, arrays, Dates, RegExps, Maps, Sets, class instances, etc.
      // are all treated as opaque leaf values
      (result as Record<string, unknown>)[fullKey] = val;
    }
  }
  // Intentionally NOT removing from `seen`: if the same object
  // appears in two branches we skip the second occurrence, which
  // is safer than risking unbounded recursion on a near-cycle.
}

export default function flattenObject(
  obj: Record<string, unknown>
): Record<string, unknown> {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: Record<string, unknown> = {};
  flatten(obj, "", new WeakSet(), result as Record<string, Scalar | unknown[]>);
  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
] as const;

function parseStrictInteger(raw: string, fieldName: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^\d+$/.test(trimmed)) {
    throw new Error(
      `Invalid integer "${raw}" in field "${fieldName}" — only non-negative integers are allowed`
    );
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isFinite(n)) {
    throw new Error(`Parsed non-finite value from "${raw}" in field "${fieldName}"`);
  }
  return n;
}

function validateBounds(value: number, config: FieldConfig): number {
  // Treat Sunday-as-7 (common cron variant) by normalizing to 0
  if (config.name === "dayOfWeek" && value === 7) {
    return 0;
  }
  if (value < config.min || value > config.max) {
    throw new Error(
      `Value ${value} is out of valid range [${config.min}–${config.max}] for field "${config.name}"`
    );
  }
  return value;
}

function buildRange(
  from: number,
  to: number,
  step: number,
  config: FieldConfig
): number[] {
  if (step <= 0) {
    throw new Error(
      `Step must be a positive integer in field "${config.name}", got ${step}`
    );
  }
  if (from > to) {
    throw new Error(
      `Range start (${from}) exceeds end (${to}) in field "${config.name}"`
    );
  }
  const result: number[] = [];
  for (let i = from; i <= to; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const s = segment.trim();

  if (s === "") {
    throw new Error(`Empty segment encountered in field "${config.name}"`);
  }

  const slashAt = s.indexOf("/");

  if (slashAt !== -1) {
    // Step expression: base/step
    const basePart = s.substring(0, slashAt);
    const stepPart = s.substring(slashAt + 1);

    if (stepPart === "" || stepPart.includes("/")) {
      throw new Error(
        `Malformed step expression "${s}" in field "${config.name}" — expected base/step`
      );
    }

    const step = parseStrictInteger(stepPart, config.name);

    if (basePart === "*") {
      // */step — full range with step
      return buildRange(config.min, config.max, step, config);
    }

    const dashAt = basePart.indexOf("-");
    if (dashAt !== -1) {
      // start-end/step
      const startRaw = basePart.substring(0, dashAt);
      const endRaw = basePart.substring(dashAt + 1);
      if (startRaw === "" || endRaw === "") {
        throw new Error(
          `Malformed range "${basePart}" in step expression "${s}" for field "${config.name}"`
        );
      }
      const from = validateBounds(parseStrictInteger(startRaw, config.name), config);
      const to = validateBounds(parseStrictInteger(endRaw, config.name), config);
      return buildRange(from, to, step, config);
    }

    // number/step — from number to field max with step
    const from = validateBounds(parseStrictInteger(basePart, config.name), config);
    return buildRange(from, config.max, step, config);
  }

  if (s === "*") {
    // Bare wildcard — all values
    return buildRange(config.min, config.max, 1, config);
  }

  const dashAt = s.indexOf("-");
  if (dashAt !== -1) {
    // Range: start-end
    const startRaw = s.substring(0, dashAt);
    const endRaw = s.substring(dashAt + 1);
    if (startRaw === "" || endRaw === "") {
      throw new Error(
        `Malformed range "${s}" in field "${config.name}" — both start and end are required`
      );
    }
    const from = validateBounds(parseStrictInteger(startRaw, config.name), config);
    const to = validateBounds(parseStrictInteger(endRaw, config.name), config);
    return buildRange(from, to, 1, config);
  }

  // Single numeric value
  const value = validateBounds(parseStrictInteger(s, config.name), config);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  const trimmed = raw?.trim();
  if (!trimmed) {
    throw new Error(`Field "${config.name}" is empty or missing`);
  }

  const segments = trimmed.split(",");

  if (segments.length === 0) {
    throw new Error(`Field "${config.name}" produced no segments — this should never happen`);
  }

  const seen = new Set<number>();

  for (const segment of segments) {
    if (segment.trim() === "") {
      throw new Error(
        `Empty comma-separated segment in field "${config.name}" — trailing or double commas are not allowed`
      );
    }
    for (const v of parseSegment(segment, config)) {
      seen.add(v);
    }
  }

  if (seen.size === 0) {
    throw new Error(`Field "${config.name}" resolved to no valid values`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (expression === null || expression === undefined) {
    throw new Error("Cron expression must not be null or undefined");
  }
  if (typeof expression !== "string") {
    throw new TypeError(
      `Cron expression must be a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty or whitespace-only");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 whitespace-separated fields, got ${fields.length} in "${expression}"`
    );
  }

  // Destructure with explicit indices to guard against accidental config mismatch
  return {
    minute: parseField(fields[0], FIELD_CONFIGS[0]),
    hour: parseField(fields[1], FIELD_CONFIGS[1]),
    dayOfMonth: parseField(fields[2], FIELD_CONFIGS[2]),
    month: parseField(fields[3], FIELD_CONFIGS[3]),
    dayOfWeek: parseField(fields[4], FIELD_CONFIGS[4]),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: Record<string, Primitive> = {}
): Record<string, Primitive> {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }
  const keys = Object.keys(obj);
  if (keys.length === 0 && prefix) {
    result[prefix] = {} as unknown as Primitive;
    return result;
  }
  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;
    flattenObject(obj[key] as NestedObject, prefix ? `${prefix}.${key}` : key, result);
  }
  return result;
}

type NestedObject = { [key: string]: unknown };

const isTraversableObject = (value: unknown): value is NestedObject =>
  value !== null &&
  typeof value === "object" &&
  !Array.isArray(value) &&
  (Object.getPrototypeOf(value) === Object.prototype ||
    Object.getPrototypeOf(value) === null);

const flattenObjectInto = (
  input: NestedObject,
  prefix: string,
  visitedNodes: WeakSet<object>,
  output: Record<string, unknown>
): Record<string, unknown> => {
  const ownKeys = Object.keys(input);

  for (const key of ownKeys) {
    const dottedKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = input[key];

    if (isTraversableObject(value)) {
      if (visitedNodes.has(value)) {
        output[dottedKey] = "[Circular]";
        continue;
      }

      const childKeys = Object.keys(value);

      if (childKeys.length === 0) {
        output[dottedKey] = value;
        continue;
      }

      visitedNodes.add(value);
      flattenObjectInto(value, dottedKey, visitedNodes, output);
      visitedNodes.delete(value);
    } else {
      output[dottedKey] = value;
    }
  }

  return output;
};

const flattenObject = (input: unknown): Record<string, unknown> => {
  if (!isTraversableObject(input)) {
    return {};
  }

  return flattenObjectInto(input, "", new WeakSet<object>(), {});
};

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: Record<string, Primitive> = {}
): Record<string, Primitive> {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }
  const keys = Object.keys(obj);
  if (keys.length === 0 && prefix) {
    result[prefix] = {} as unknown as Primitive;
    return result;
  }
  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;
    const newKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];
    val !== null && typeof val === "object" && !Array.isArray(val)
      ? flattenObject(val as NestedObject, newKey, result)
      : (result[newKey] = val as Primitive);
  }
  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldSpec {
  name: keyof CronFields;
  min: number;
  max: number;
}

const FIELD_SPECS: readonly FieldSpec[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
] as const;

class CronParseError extends Error {
  constructor(message: string) {
    super(`CronParseError: ${message}`);
    this.name = "CronParseError";
  }
}

function assertInteger(value: number, context: string): void {
  if (!Number.isInteger(value)) {
    throw new CronParseError(`Non-integer value in ${context}: ${value}`);
  }
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new CronParseError(
      `Value ${value} out of range [${min}, ${max}] in ${context}`
    );
  }
}

function parseNumber(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^-?\d+$/.test(trimmed)) {
    throw new CronParseError(`Expected integer in ${context}, got: "${trimmed}"`);
  }
  const n = Number(trimmed);
  assertInteger(n, context);
  return n;
}

function deduplicateSorted(values: number[]): number[] {
  return Array.from(new Set(values)).sort((a, b) => a - b);
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  const context = `field "${fieldName}"`;
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new CronParseError(`Empty segment in ${context}`);
  }

  // Step value: "*/step" or "range/step"
  if (trimmed.includes("/")) {
    const slashParts = trimmed.split("/");
    if (slashParts.length !== 2) {
      throw new CronParseError(`Multiple slashes in segment "${trimmed}" of ${context}`);
    }

    const [rangePart, stepRaw] = slashParts;
    const step = parseNumber(stepRaw, `${context} step`);

    if (step <= 0) {
      throw new CronParseError(`Step must be >= 1 in ${context}, got: ${step}`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      const dashParts = rangePart.split("-");
      if (dashParts.length !== 2) {
        throw new CronParseError(`Invalid range "${rangePart}" in ${context}`);
      }
      rangeMin = parseNumber(dashParts[0], `${context} range start`);
      rangeMax = parseNumber(dashParts[1], `${context} range end`);
      assertInRange(rangeMin, min, max, `${context} range start`);
      assertInRange(rangeMax, min, max, `${context} range end`);
      if (rangeMin > rangeMax) {
        throw new CronParseError(
          `Range start ${rangeMin} > range end ${rangeMax} in ${context}`
        );
      }
    } else {
      // single number with step: "5/15" means starting at 5, step by 15
      rangeMin = parseNumber(rangePart, `${context} step base`);
      rangeMax = max;
      assertInRange(rangeMin, min, max, `${context} step base`);
    }

    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      values.push(v);
    }

    if (values.length === 0) {
      throw new CronParseError(`Step expression produced no values in ${context}`);
    }

    return values;
  }

  // Wildcard
  if (trimmed === "*") {
    const values: number[] = [];
    for (let v = min; v <= max; v++) {
      values.push(v);
    }
    return values;
  }

  // Range: "1-5"
  if (trimmed.includes("-")) {
    const dashParts = trimmed.split("-");
    if (dashParts.length !== 2) {
      throw new CronParseError(`Invalid range "${trimmed}" in ${context}`);
    }
    const rangeMin = parseNumber(dashParts[0], `${context} range start`);
    const rangeMax = parseNumber(dashParts[1], `${context} range end`);
    assertInRange(rangeMin, min, max, `${context} range start`);
    assertInRange(rangeMax, min, max, `${context} range end`);
    if (rangeMin > rangeMax) {
      throw new CronParseError(
        `Range start ${rangeMin} > range end ${rangeMax} in ${context}`
      );
    }
    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v++) {
      values.push(v);
    }
    return values;
  }

  // Single number
  const n = parseNumber(trimmed, context);
  assertInRange(n, min, max, context);
  return [n];
}

function parseField(raw: string, spec: FieldSpec): number[] {
  const trimmed = raw.trim();

  if (trimmed === "") {
    throw new CronParseError(`Empty field "${spec.name}"`);
  }

  // Comma-separated list (each part handled individually)
  const parts = trimmed.split(",");

  if (parts.length === 0) {
    throw new CronParseError(`No parts found in field "${spec.name}"`);
  }

  const allValues: number[] = [];

  for (const part of parts) {
    if (part.trim() === "") {
      throw new CronParseError(`Empty item in comma list of field "${spec.name}"`);
    }
    const values = parseSegment(part, spec.min, spec.max, spec.name);
    allValues.push(...values);
  }

  return deduplicateSorted(allValues);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new CronParseError(`Expression must be a string, got: ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new CronParseError("Expression is empty");
  }

  // Split on whitespace — allow multiple spaces/tabs between fields
  const rawFields = trimmed.split(/\s+/);

  if (rawFields.length !== 5) {
    throw new CronParseError(
      `Expected exactly 5 fields, got ${rawFields.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_SPECS.length; i++) {
    const spec = FIELD_SPECS[i];
    const rawField = rawFields[i];
    result[spec.name] = parseField(rawField, spec);
  }

  return result;
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(field: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of field.split(",")) {
    const trimmed = part.trim();

    // Step: */n or a-b/n
    if (trimmed.includes("/")) {
      const [rangePart, stepPart] = trimmed.split("/");
      const step = parseInt(stepPart, 10);

      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: ${stepPart}`);
      }

      let rangeMin = min;
      let rangeMax = max;

      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [lo, hi] = rangePart.split("-").map(Number);
          rangeMin = clamp(lo, min, max);
          rangeMax = clamp(hi, min, max);
          if (rangeMin > rangeMax) {
            throw new RangeError(`Invalid range: ${rangePart}`);
          }
        } else {
          rangeMin = clamp(parseInt(rangePart, 10), min, max);
          rangeMax = max;
        }
      }

      for (let i = rangeMin; i <= rangeMax; i += step) {
        results.add(i);
      }
      continue;
    }

    // Wildcard
    if (trimmed === "*") {
      for (let i = min; i <= max; i++) {
        results.add(i);
      }
      continue;
    }

    // Range: a-b
    if (trimmed.includes("-")) {
      const [lo, hi] = trimmed.split("-").map(Number);
      const rangeMin = clamp(lo, min, max);
      const rangeMax = clamp(hi, min, max);
      if (rangeMin > rangeMax) {
        throw new RangeError(`Invalid range: ${trimmed}`);
      }
      for (let i = rangeMin; i <= rangeMax; i++) {
        results.add(i);
      }
      continue;
    }

    // Single number
    const num = parseInt(trimmed, 10);
    if (isNaN(num)) {
      throw new Error(`Invalid cron field value: ${trimmed}`);
    }
    results.add(clamp(num, min, max));
  }

  return Array.from(results).sort((a, b) => a - b);
}

function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = parts;
  const fields = Object.keys(FIELD_RANGES) as Array<keyof CronResult>;

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteField,
    hourField,
    domField,
    monthField,
    dowField,
  ].map((field, i) => {
    const key = fields[i];
    const [min, max] = FIELD_RANGES[key];
    return parseField(field, min, max);
  });

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export default parseCron;

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

type CronField = keyof CronExpression;

const FIELD_CONFIGS: Record<CronField, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER: readonly CronField[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function parseStrictInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Expected a non-negative integer for ${context}, got '${raw}'`);
  }
  const n = parseInt(raw, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer overflow for ${context}: '${raw}'`);
  }
  return n;
}

function assertInBounds(value: number, config: FieldConfig, fieldName: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of range [${config.min}, ${config.max}] for field '${fieldName}'`
    );
  }
}

function buildRange(start: number, end: number): number[] {
  if (start > end) {
    throw new RangeError(`Range start (${start}) must not exceed end (${end})`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i++) {
    values.push(i);
  }
  return values;
}

function buildStep(start: number, end: number, step: number): number[] {
  if (step <= 0) {
    throw new RangeError(`Step value must be a positive integer, got ${step}`);
  }
  if (start > end) {
    throw new RangeError(`Step range start (${start}) must not exceed end (${end})`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseToken(token: string, config: FieldConfig, fieldName: string): number[] {
  if (!token) {
    throw new Error(`Empty token encountered in field '${fieldName}'`);
  }

  // Step expression: */n  |  n-m/n  |  n/n
  if (token.includes("/")) {
    const slashCount = (token.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new Error(`Invalid step expression '${token}' in field '${fieldName}': multiple slashes`);
    }
    const [rangePart, stepStr] = token.split("/");
    const step = parseStrictInt(stepStr, `step in '${token}'`);
    if (step === 0) {
      throw new RangeError(`Step value must not be zero in '${token}' for field '${fieldName}'`);
    }

    if (rangePart === "*") {
      return buildStep(config.min, config.max, step);
    }

    if (rangePart.includes("-")) {
      const dashCount = (rangePart.match(/-/g) ?? []).length;
      if (dashCount !== 1) {
        throw new Error(`Invalid range '${rangePart}' in field '${fieldName}'`);
      }
      const [startStr, endStr] = rangePart.split("-");
      const start = parseStrictInt(startStr, `range start in '${token}'`);
      const end   = parseStrictInt(endStr,   `range end in '${token}'`);
      assertInBounds(start, config, fieldName);
      assertInBounds(end,   config, fieldName);
      return buildStep(start, end, step);
    }

    // n/step — treat n as start, max as end (standard cron behaviour)
    const start = parseStrictInt(rangePart, `value in '${token}'`);
    assertInBounds(start, config, fieldName);
    return buildStep(start, config.max, step);
  }

  // Wildcard
  if (token === "*") {
    return buildRange(config.min, config.max);
  }

  // Range: n-m
  if (token.includes("-")) {
    const dashCount = (token.match(/-/g) ?? []).length;
    if (dashCount !== 1) {
      throw new Error(`Invalid range expression '${token}' in field '${fieldName}'`);
    }
    const [startStr, endStr] = token.split("-");
    const start = parseStrictInt(startStr, `range start in '${token}'`);
    const end   = parseStrictInt(endStr,   `range end in '${token}'`);
    assertInBounds(start, config, fieldName);
    assertInBounds(end,   config, fieldName);
    return buildRange(start, end);
  }

  // Single numeric value
  const value = parseStrictInt(token, `value in field '${fieldName}'`);
  assertInBounds(value, config, fieldName);
  return [value];
}

function parseField(raw: string, config: FieldConfig, fieldName: string): number[] {
  const trimmed = raw.trim();
  if (!trimmed) {
    throw new Error(`Field '${fieldName}' is empty or whitespace-only`);
  }

  if (trimmed.includes(",")) {
    const parts = trimmed.split(",");
    const seen = new Set<number>();

    for (const part of parts) {
      const stripped = part.trim();
      if (!stripped) {
        throw new Error(
          `Empty value in comma-separated list for field '${fieldName}'`
        );
      }
      for (const v of parseToken(stripped, config, fieldName)) {
        seen.add(v);
      }
    }

    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseToken(trimmed, config, fieldName);
}

export default function parseCron(expression: string): CronExpression {
  if (expression === null || expression === undefined) {
    throw new TypeError(`parseCron requires a string argument, got ${expression}`);
  }
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron requires a string argument, got ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (got ${fields.length}): "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const config    = FIELD_CONFIGS[fieldName];
    const raw       = fields[i];

    try {
      result[fieldName] = parseField(raw, config, fieldName);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Error parsing field '${fieldName}' (value: '${raw}'): ${message}`);
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlattenedObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value) ? (value as unknown as Primitive) : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: unknown };

function flatten(obj: NestedObject, prefix: string, result: FlatObject): void {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flatten(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value;
    }
  }
}

export default function flattenObject(obj: NestedObject): FlatObject {
  const result: FlatObject = {};
  flatten(obj, "", result);
  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (segment === "*") {
    return range(min, max);
  }

  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value in: ${segment}`);
    const result: number[] = [];
    for (let i = min; i <= max; i += step) result.push(i);
    return result;
  }

  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value in: ${segment}`);
    const [startStr, endStr] = rangePart.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new RangeError(`Range start ${start} > end ${end} in field ${field}`);
    return range(start, end);
  }

  if (segment.includes(",")) {
    return segment.split(",").flatMap(part => parseSegment(part.trim(), field));
  }

  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value "${segment}" in field ${field}`);
  clamp(value, min, max);
  return [value];
}

function dedupe(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  return {
    minute: dedupe(parseSegment(minuteField, "minute")),
    hour: dedupe(parseSegment(hourField, "hour")),
    dayOfMonth: dedupe(parseSegment(domField, "dayOfMonth")),
    month: dedupe(parseSegment(monthField, "month")),
    dayOfWeek: dedupe(parseSegment(dowField, "dayOfWeek")),
  };
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseField(expr: string, min: number, max: number): number[] {
  if (expr === "*") {
    return range(min, max);
  }

  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${expr}`);
    }
    return range(min, max).filter((v) => (v - min) % step === 0);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in: ${expr}`);
    }
    const [rangeStart, rangeEnd] = rangePart.includes("-")
      ? rangePart.split("-").map((n) => parseInt(n, 10))
      : [parseInt(rangePart, 10), max];
    if (isNaN(rangeStart) || isNaN(rangeEnd)) {
      throw new Error(`Invalid range in: ${expr}`);
    }
    return range(rangeStart, rangeEnd).filter((v) => (v - rangeStart) % step === 0);
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${expr}`);
    }
    if (start > end) {
      throw new Error(`Range start exceeds end: ${expr}`);
    }
    if (start < min || end > max) {
      throw new Error(`Range ${expr} out of bounds [${min}, ${max}]`);
    }
    return range(start, end);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value: ${expr}`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}, ${max}]`);
  }
  return [value];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const exprs = [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr];

  const result = {} as CronResult;
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(exprs[i], min, max);
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(
  field: string,
  fieldName: keyof CronFields
): number[] {
  const { min, max } = FIELD_RANGES[fieldName];

  // Normalize dayOfWeek: treat 7 as 0 (Sunday) after parsing
  const normalize = (v: number): number => {
    if (fieldName === "dayOfWeek" && v === 7) return 0;
    return v;
  };

  // Wildcard: all values
  if (field === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Step on wildcard: */step
  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in field "${field}"`);
    }
    const result: number[] = [];
    for (let i = min; i <= max; i += step) {
      result.push(i);
    }
    return result;
  }

  // Comma-separated list: recurse on each part
  if (field.includes(",")) {
    const parts = field.split(",");
    const seen = new Set<number>();
    const result: number[] = [];
    for (const part of parts) {
      for (const val of parseField(part.trim(), fieldName)) {
        if (!seen.has(val)) {
          seen.add(val);
          result.push(val);
        }
      }
    }
    return result.sort((a, b) => a - b);
  }

  // Range with optional step: start-end[/step]
  if (field.includes("-")) {
    const [rangePart, stepPart] = field.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = clamp(normalize(parseInt(startStr, 10)), min, max);
    const end = clamp(normalize(parseInt(endStr, 10)), min, max);
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range in field "${field}"`);
    }
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step in range field "${field}"`);
    }
    if (start > end) {
      throw new Error(`Range start ${start} is greater than end ${end} in field "${field}"`);
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) {
      result.push(i);
    }
    return result;
  }

  // Step on a specific start: start/step
  if (field.includes("/")) {
    const [startStr, stepStr] = field.split("/");
    const start = clamp(normalize(parseInt(startStr, 10)), min, max);
    const step = parseInt(stepStr, 10);

    if (isNaN(start) || isNaN(step) || step <= 0) {
      throw new Error(`Invalid step expression in field "${field}"`);
    }

    const result: number[] = [];
    for (let i = start; i <= max; i += step) {
      result.push(i);
    }
    return result;
  }

  // Single numeric value
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value "${field}"`);
  }

  const normalized = normalize(value);
  clamp(normalized, min, max);
  return [normalized];
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = parts;
  const fieldNames: (keyof CronFields)[] = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ];
  const rawFields = [minuteField, hourField, domField, monthField, dowField];

  const result = {} as CronFields;
  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const raw = rawFields[i];
    try {
      result[name] = parseField(raw, name);
    } catch (err) {
      throw new Error(
        `Error parsing ${name} field "${raw}": ${(err as Error).message}`
      );
    }
  }

  // Deduplicate dayOfWeek (7 normalized to 0 may cause duplicates)
  result.dayOfWeek = [...new Set(result.dayOfWeek)].sort((a, b) => a - b);

  return result;
}

export default parseCron;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  readonly min: number;
  readonly max: number;
}

const FIELD_RANGES: Readonly<Record<keyof CronExpression, FieldRange>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

const FIELD_ORDER = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function parseNonNegativeInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  // Strictly digits only — reject leading signs, decimals, empty strings, whitespace
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Invalid integer "${raw}" in ${context}`);
  }
  const n = parseInt(trimmed, 10);
  // Guard against pathological values that pass the regex but overflow to Infinity
  if (!Number.isFinite(n)) {
    throw new Error(`Integer overflow for "${raw}" in ${context}`);
  }
  return n;
}

function assertInRange(value: number, range: FieldRange, context: string): void {
  if (value < range.min || value > range.max) {
    throw new RangeError(
      `Value ${value} out of valid range [${range.min}–${range.max}] in ${context}`,
    );
  }
}

/**
 * Parses a single non-comma token, which may be:
 *   *           – wildcard
 *   N           – single value
 *   N-M         – inclusive range
 *   * /step     – wildcard with step  (note: space added to avoid JSDoc issue)
 *   N/step      – start-to-max with step
 *   N-M/step    – range with step
 */
function parseToken(token: string, range: FieldRange, fieldName: string): number[] {
  const context = `field "${fieldName}" token "${token}"`;

  // ── Extract optional step ────────────────────────────────────────────────
  let step: number | undefined;
  let baseExpr = token;

  const slashPos = token.indexOf("/");
  if (slashPos !== -1) {
    const stepStr = token.slice(slashPos + 1);
    baseExpr = token.slice(0, slashPos);

    // Guard against chained slashes like "*/5/2"
    if (stepStr.includes("/")) {
      throw new Error(`Multiple step operators in ${context}`);
    }

    step = parseNonNegativeInteger(stepStr, context);
    if (step === 0) {
      throw new Error(`Step value must be ≥ 1 in ${context}`);
    }
  }

  // ── Resolve start/end ────────────────────────────────────────────────────
  let start: number;
  let end: number;

  if (baseExpr === "*") {
    start = range.min;
    end = range.max;
  } else {
    const dashPos = baseExpr.indexOf("-");
    if (dashPos !== -1) {
      // Reject ambiguous patterns like "-5" or "1-5-3"
      if (dashPos === 0) {
        throw new Error(`Negative values are not permitted in ${context}`);
      }
      const startStr = baseExpr.slice(0, dashPos);
      const endStr   = baseExpr.slice(dashPos + 1);

      if (endStr.includes("-")) {
        throw new Error(`Malformed range expression in ${context}`);
      }

      start = parseNonNegativeInteger(startStr, context);
      end   = parseNonNegativeInteger(endStr,   context);

      assertInRange(start, range, context);
      assertInRange(end,   range, context);

      if (start > end) {
        throw new RangeError(
          `Range start (${start}) must not exceed range end (${end}) in ${context}`,
        );
      }
    } else {
      // Single numeric value
      start = parseNonNegativeInteger(baseExpr, context);
      assertInRange(start, range, context);
      // With a step, treat "N/step" as "N–max/step" (POSIX-compatible behaviour)
      end = step !== undefined ? range.max : start;
    }
  }

  // ── Expand to value array ────────────────────────────────────────────────
  const values: number[] = [];
  const increment = step ?? 1;

  for (let v = start; v <= end; v += increment) {
    values.push(v);
  }

  // A well-formed token should always produce at least one value
  if (values.length === 0) {
    throw new Error(`Token produced no values in ${context}`);
  }

  return values;
}

/**
 * Parses a single cron field expression (may contain comma-separated tokens).
 * Returns a sorted, deduplicated array of valid integer values.
 */
function parseField(
  fieldStr: string,
  range: FieldRange,
  fieldName: string,
): number[] {
  if (typeof fieldStr !== "string" || fieldStr.trim() === "") {
    throw new Error(`Field "${fieldName}" is empty or missing`);
  }

  const tokens = fieldStr.split(",");
  const seen = new Set<number>();

  for (const raw of tokens) {
    const token = raw.trim();
    if (token === "") {
      throw new Error(
        `Empty token (trailing/leading comma?) in field "${fieldName}"`,
      );
    }
    for (const v of parseToken(token, range, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

/**
 * Parses a 5-field cron expression string into a structured object whose
 * properties each hold the sorted array of all matching integer values.
 *
 * Field order:  minute  hour  dayOfMonth  month  dayOfWeek
 * Valid ranges: 0–59    0–23  1–31        1–12   0–6
 *
 * Supported token syntax per field:
 *   *          every value in range
 *   N          exact value
 *   N-M        inclusive range
 *   * /step    every Nth value across the full range
 *   N/step     from N to range-max, stepping by N
 *   N-M/step   range with step
 *   a,b,c      comma-separated list of any of the above
 *
 * @throws {Error | RangeError} on any malformed or out-of-range input
 */
export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`,
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  // Split on any run of whitespace; a correct expression has exactly 5 tokens
  const parts = trimmed.split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (got ${parts.length}): "${expression}"`,
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    result[name] = parseField(parts[i], FIELD_RANGES[name], name);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix: string = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : String(index);
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) {
      result[prefix] = null;
    }
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      flattenObject(value as unknown as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both represent Sunday
};

const FIELD_ORDER: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function isNonNegativeInteger(s: string): boolean {
  return /^\d+$/.test(s);
}

function parseInteger(s: string, context: string): number {
  if (!isNonNegativeInteger(s)) {
    throw new RangeError(`Expected a non-negative integer but got "${s}" in ${context}`);
  }
  return parseInt(s, 10);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}] in ${context}`);
  }
}

function expandRange(start: number, end: number, step: number, fieldName: FieldName): number[] {
  const { min, max } = FIELD_RANGES[fieldName];
  const context = `field "${fieldName}"`;

  assertInRange(start, min, max, context);
  assertInRange(end, min, max, context);

  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end} in ${context}`);
  }
  if (step < 1) {
    throw new RangeError(`Step must be >= 1 but got ${step} in ${context}`);
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSingleSegment(segment: string, fieldName: FieldName): number[] {
  const { min, max } = FIELD_RANGES[fieldName];
  const context = `field "${fieldName}"`;

  // Step value: */N or R-R/N or N/N
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Invalid step expression "${segment}" in ${context} — exactly one "/" is allowed`);
    }
    const [rangeStr, stepStr] = slashParts;
    const step = parseInteger(stepStr, `${context} step`);
    if (step < 1) {
      throw new RangeError(`Step must be >= 1 but got ${step} in ${context}`);
    }

    if (rangeStr === "*") {
      return expandRange(min, max, step, fieldName);
    }

    if (rangeStr.includes("-")) {
      const dashParts = rangeStr.split("-");
      if (dashParts.length !== 2) {
        throw new SyntaxError(`Invalid range "${rangeStr}" in ${context}`);
      }
      const start = parseInteger(dashParts[0], context);
      const end   = parseInteger(dashParts[1], context);
      return expandRange(start, end, step, fieldName);
    }

    // N/step — start from N, step to max
    const start = parseInteger(rangeStr, context);
    return expandRange(start, max, step, fieldName);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max, 1, fieldName);
  }

  // Range: N-M
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in ${context} — exactly one "-" is allowed`);
    }
    const start = parseInteger(dashParts[0], context);
    const end   = parseInteger(dashParts[1], context);
    return expandRange(start, end, 1, fieldName);
  }

  // Single integer
  const value = parseInteger(segment, context);
  assertInRange(value, min, max, context);
  return [value];
}

function parseField(raw: string, fieldName: FieldName): number[] {
  if (typeof raw !== "string" || raw.trim() === "") {
    throw new TypeError(`Field "${fieldName}" must be a non-empty string, got: ${JSON.stringify(raw)}`);
  }

  const trimmed = raw.trim();

  // Comma-separated list — none of the individual segments may themselves contain commas
  const segments = trimmed.split(",");
  if (segments.some((s) => s.trim() === "")) {
    throw new SyntaxError(`Empty segment in comma list for field "${fieldName}": "${trimmed}"`);
  }

  const collected: number[] = segments.flatMap((s) => parseSingleSegment(s.trim(), fieldName));

  // Deduplicate and sort; for dayOfWeek normalise 7 → 0 (both mean Sunday)
  const normalised = fieldName === "dayOfWeek"
    ? collected.map((v) => (v === 7 ? 0 : v))
    : collected;

  return [...new Set(normalised)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  // Collapse runs of whitespace and trim; reject empty input
  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("parseCron received an empty string");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `parseCron expects exactly 5 space-separated fields (minute hour dayOfMonth month dayOfWeek), got ${parts.length}: "${expression}"`
    );
  }

  // Parse all fields; accumulate errors so the caller sees everything wrong at once
  const errors: string[] = [];
  const parsed: Partial<CronExpression> = {};

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    try {
      parsed[fieldName] = parseField(parts[i], fieldName);
    } catch (err) {
      errors.push(err instanceof Error ? err.message : String(err));
    }
  }

  if (errors.length > 0) {
    throw new RangeError(`Invalid cron expression:\n  ${errors.join("\n  ")}`);
  }

  return parsed as CronExpression;
}

const FIELDS = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
] as const;

type CronResult = Record<(typeof FIELDS)[number]["name"], number[]>;

function parseField(expr: string, min: number, max: number): number[] {
  const range = (a: number, b: number) =>
    Array.from({ length: b - a + 1 }, (_, i) => a + i);
  const clamp = (n: number) => {
    if (n < min || n > max) throw new RangeError(`${n} out of [${min},${max}]`);
    return n;
  };
  if (expr === "*") return range(min, max);
  if (expr.startsWith("*/")) {
    const step = Number(expr.slice(2));
    if (!step || step < 1) throw new Error(`Invalid step: ${expr}`);
    return range(min, max).filter((v) => (v - min) % step === 0);
  }
  if (expr.includes(",")) return expr.split(",").flatMap((e) => parseField(e.trim(), min, max));
  if (expr.includes("-")) {
    const [a, b] = expr.split("-").map(Number);
    return range(clamp(a), clamp(b));
  }
  return [clamp(Number(expr))];
}

export default function parseCron(expr: string): CronResult {
  const parts = expr.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);
  return Object.fromEntries(
    FIELDS.map(({ name, min, max }, i) => [name, parseField(parts[i], min, max)])
  ) as CronResult;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type FlattenedObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function isTraversable(value: unknown): value is Record<string, unknown> | unknown[] {
  if (Array.isArray(value)) return true;
  return isPlainObject(value);
}

function flattenInternal(
  input: Record<string, unknown> | unknown[],
  prefix: string,
  seen: WeakSet<object>,
  result: FlattenedObject,
): void {
  const asObj = input as object;

  if (seen.has(asObj)) {
    throw new Error(
      `Circular reference detected${prefix ? ` at path "${prefix}"` : ""}`,
    );
  }
  seen.add(asObj);

  const entries: Array<[string, unknown]> = Array.isArray(input)
    ? input.map((v, i) => [String(i), v])
    : Object.entries(input);

  if (entries.length === 0) {
    // Empty object or array: preserve as a leaf so callers can detect it
    if (prefix !== "") result[prefix] = input;
  } else {
    for (const [key, value] of entries) {
      const newKey = prefix !== "" ? `${prefix}.${key}` : key;

      const valueIsTraversable = isTraversable(value);
      const valueIsEmpty = valueIsTraversable
        ? Array.isArray(value)
          ? (value as unknown[]).length === 0
          : Object.keys(value as object).length === 0
        : false;

      if (valueIsTraversable && !valueIsEmpty) {
        flattenInternal(
          value as Record<string, unknown> | unknown[],
          newKey,
          seen,
          result,
        );
      } else {
        result[newKey] = value;
      }
    }
  }

  seen.delete(asObj);
}

function flattenObject(obj: Record<string, unknown>): FlattenedObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`,
    );
  }

  const result: FlattenedObject = {};
  flattenInternal(obj, "", new WeakSet(), result);
  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldBounds {
  min: number;
  max: number;
  name: string;
}

const FIELD_BOUNDS: readonly [FieldBounds, FieldBounds, FieldBounds, FieldBounds, FieldBounds] = [
  { min: 0,  max: 59, name: "minute"     },
  { min: 0,  max: 23, name: "hour"       },
  { min: 1,  max: 31, name: "dayOfMonth" },
  { min: 1,  max: 12, name: "month"      },
  { min: 0,  max: 6,  name: "dayOfWeek"  },
] as const;

function parseStrictInt(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Invalid non-integer value "${raw}" in ${context}`);
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer overflow for value "${raw}" in ${context}`);
  }
  return n;
}

function assertInBounds(value: number, bounds: FieldBounds): void {
  if (value < bounds.min || value > bounds.max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${bounds.min}–${bounds.max}] for field "${bounds.name}"`
    );
  }
}

function expandStep(start: number, end: number, step: number, bounds: FieldBounds): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step} in field "${bounds.name}"`);
  }
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${bounds.name}"`
    );
  }
  assertInBounds(start, bounds);
  assertInBounds(end, bounds);

  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

function parsePart(part: string, bounds: FieldBounds): number[] {
  const ctx = `field "${bounds.name}"`;

  if (part === "") {
    throw new Error(`Empty part encountered in ${ctx}`);
  }

  // Step: base/step  where base is *, a number, or a range
  const slashIdx = part.indexOf("/");
  if (slashIdx !== -1) {
    const baseRaw = part.slice(0, slashIdx);
    const stepRaw = part.slice(slashIdx + 1);

    if (stepRaw.includes("/")) {
      throw new Error(`Multiple slash operators in "${part}" in ${ctx}`);
    }

    const step = parseStrictInt(stepRaw, ctx);
    if (step === 0) {
      throw new RangeError(`Step value must not be zero in ${ctx}`);
    }

    if (baseRaw === "*") {
      return expandStep(bounds.min, bounds.max, step, bounds);
    }

    const dashIdx = baseRaw.indexOf("-");
    if (dashIdx > 0) {
      const start = parseStrictInt(baseRaw.slice(0, dashIdx), ctx);
      const end   = parseStrictInt(baseRaw.slice(dashIdx + 1), ctx);
      return expandStep(start, end, step, bounds);
    }

    const start = parseStrictInt(baseRaw, ctx);
    assertInBounds(start, bounds);
    return expandStep(start, bounds.max, step, bounds);
  }

  // Wildcard
  if (part === "*") {
    return expandStep(bounds.min, bounds.max, 1, bounds);
  }

  // Range: start-end (dash must not be at position 0)
  const dashIdx = part.indexOf("-");
  if (dashIdx > 0) {
    const startRaw = part.slice(0, dashIdx);
    const endRaw   = part.slice(dashIdx + 1);

    if (endRaw.includes("-")) {
      throw new Error(`Multiple dash operators in range "${part}" in ${ctx}`);
    }

    const start = parseStrictInt(startRaw, ctx);
    const end   = parseStrictInt(endRaw,   ctx);
    return expandStep(start, end, 1, bounds);
  }

  // Single value
  const value = parseStrictInt(part, ctx);
  assertInBounds(value, bounds);
  return [value];
}

function parseFieldExpression(expression: string, bounds: FieldBounds): number[] {
  if (expression === "") {
    throw new Error(`Empty expression for field "${bounds.name}"`);
  }

  const parts = expression.split(",");
  if (parts.length === 0) {
    throw new Error(`No parts found in expression "${expression}" for field "${bounds.name}"`);
  }

  const valueSet = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new Error(`Empty list item in expression "${expression}" for field "${bounds.name}"`);
    }
    const expanded = parsePart(trimmed, bounds);
    for (const v of expanded) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${trimmed}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const [minuteBounds, hourBounds, domBounds, monthBounds, dowBounds] = FIELD_BOUNDS;

  return {
    minute:     parseFieldExpression(minuteExpr, minuteBounds),
    hour:       parseFieldExpression(hourExpr,   hourBounds),
    dayOfMonth: parseFieldExpression(domExpr,    domBounds),
    month:      parseFieldExpression(monthExpr,  monthBounds),
    dayOfWeek:  parseFieldExpression(dowExpr,    dowBounds),
  };
}

interface CronFieldBounds {
  readonly name: string;
  readonly min: number;
  readonly max: number;
}

export interface CronExpression {
  readonly minute: number[];
  readonly hour: number[];
  readonly dayOfMonth: number[];
  readonly month: number[];
  readonly dayOfWeek: number[];
}

const FIELD_BOUNDS = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 6  },
] as const satisfies readonly CronFieldBounds[];

const integerFromString = (raw: string, location: string): number => {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Non-integer token "${trimmed}" at ${location}`);
  }
  const parsed = parseInt(trimmed, 10);
  if (!Number.isFinite(parsed)) {
    throw new Error(`Unparseable integer "${trimmed}" at ${location}`);
  }
  return parsed;
};

const withinBounds = (value: number, bounds: CronFieldBounds, location: string): number => {
  if (value < bounds.min || value > bounds.max) {
    throw new Error(
      `Value ${value} falls outside [${bounds.min}, ${bounds.max}] for field "${bounds.name}" at ${location}`
    );
  }
  return value;
};

const integerSequence = (
  from: number,
  to: number,
  step: number,
  bounds: CronFieldBounds,
  location: string
): number[] => {
  if (step <= 0) {
    throw new Error(`Step must be a positive integer, got ${step} at ${location}`);
  }
  if (from > to) {
    throw new Error(
      `Range start ${from} exceeds range end ${to} in field "${bounds.name}" at ${location}`
    );
  }
  const result: number[] = [];
  for (let cursor = from; cursor <= to; cursor += step) {
    result.push(cursor);
  }
  return result;
};

const expandSegment = (segment: string, bounds: CronFieldBounds): number[] => {
  const location = `segment "${segment}" in field "${bounds.name}"`;

  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new Error(`Malformed step expression at ${location}`);
    }
    const [baseToken, stepToken] = slashParts;
    const step = integerFromString(stepToken, `step of ${location}`);
    if (step === 0) {
      throw new Error(`Step value of zero produces no results at ${location}`);
    }

    if (baseToken === "*") {
      return integerSequence(bounds.min, bounds.max, step, bounds, location);
    }

    if (baseToken.includes("-")) {
      const dashParts = baseToken.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Malformed range in base of ${location}`);
      }
      const from = withinBounds(
        integerFromString(dashParts[0], `range start of ${location}`),
        bounds,
        location
      );
      const to = withinBounds(
        integerFromString(dashParts[1], `range end of ${location}`),
        bounds,
        location
      );
      return integerSequence(from, to, step, bounds, location);
    }

    const from = withinBounds(
      integerFromString(baseToken, `offset base of ${location}`),
      bounds,
      location
    );
    return integerSequence(from, bounds.max, step, bounds, location);
  }

  if (segment === "*") {
    return integerSequence(bounds.min, bounds.max, 1, bounds, location);
  }

  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new Error(`Malformed range at ${location}`);
    }
    const from = withinBounds(
      integerFromString(dashParts[0], `range start of ${location}`),
      bounds,
      location
    );
    const to = withinBounds(
      integerFromString(dashParts[1], `range end of ${location}`),
      bounds,
      location
    );
    return integerSequence(from, to, 1, bounds, location);
  }

  const singleValue = withinBounds(
    integerFromString(segment, location),
    bounds,
    location
  );
  return [singleValue];
};

const expandField = (field: string, bounds: CronFieldBounds): number[] => {
  if (!field || field.trim().length === 0) {
    throw new Error(`Field "${bounds.name}" is empty`);
  }

  const commaSegments = field.split(",");
  const accumulated = new Set<number>();

  for (const segment of commaSegments) {
    const trimmed = segment.trim();
    if (trimmed.length === 0) {
      throw new Error(`Empty segment in comma list for field "${bounds.name}"`);
    }
    for (const value of expandSegment(trimmed, bounds)) {
      accumulated.add(value);
    }
  }

  return Array.from(accumulated).sort((a, b) => a - b);
};

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string" || expression.trim().length === 0) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression requires exactly 5 fields; received ${fields.length} in "${expression}"`
    );
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] = fields;

  return {
    minute:     expandField(minuteField,     FIELD_BOUNDS[0]),
    hour:       expandField(hourField,       FIELD_BOUNDS[1]),
    dayOfMonth: expandField(dayOfMonthField, FIELD_BOUNDS[2]),
    month:      expandField(monthField,      FIELD_BOUNDS[3]),
    dayOfWeek:  expandField(dayOfWeekField,  FIELD_BOUNDS[4]),
  };
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof CronExpression;

interface FieldBounds {
  readonly min: number;
  readonly max: number;
}

const FIELD_ORDER: readonly CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

const FIELD_BOUNDS: Readonly<Record<CronField, FieldBounds>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

// Matches: *, N, N-M, */S, N/S, N-M/S
const TOKEN_PATTERN = /^(\*|\d+(?:-\d+)?)(?:\/(\d+))?$/;

function integerFromDigits(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Expected non-negative integer digits, got "${raw}" in "${context}"`);
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer value overflows safe range for "${raw}" in "${context}"`);
  }
  return n;
}

function integerWithinBounds(value: number, bounds: FieldBounds, context: string): number {
  if (value < bounds.min || value > bounds.max) {
    throw new Error(
      `Value ${value} falls outside [${bounds.min}, ${bounds.max}] in "${context}"`
    );
  }
  return value;
}

function inclusiveRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) {
    result.push(i);
  }
  return result;
}

function expandToken(token: string, bounds: FieldBounds): number[] {
  const trimmed = token.trim();
  if (trimmed.length === 0) {
    throw new Error(`Empty token — field contains trailing, leading, or adjacent commas`);
  }

  const match = TOKEN_PATTERN.exec(trimmed);
  if (match === null) {
    throw new Error(
      `Unrecognized token format "${trimmed}". ` +
      `Expected *, N, N-M, */S, N/S, or N-M/S`
    );
  }

  const basePart = match[1];
  const stepStr  = match[2];

  if (stepStr !== undefined) {
    const step = integerFromDigits(stepStr, trimmed);
    if (step === 0) {
      throw new Error(`Step value of zero produces infinite sequence in "${trimmed}"`);
    }
  }

  const step = stepStr !== undefined ? parseInt(stepStr, 10) : 1;

  let baseValues: number[];

  if (basePart === "*") {
    baseValues = inclusiveRange(bounds.min, bounds.max);
  } else {
    const dashIndex = basePart.indexOf("-");

    if (dashIndex !== -1) {
      const startRaw = basePart.slice(0, dashIndex);
      const endRaw   = basePart.slice(dashIndex + 1);

      const rangeStart = integerWithinBounds(
        integerFromDigits(startRaw, trimmed),
        bounds,
        trimmed
      );
      const rangeEnd = integerWithinBounds(
        integerFromDigits(endRaw, trimmed),
        bounds,
        trimmed
      );

      if (rangeStart > rangeEnd) {
        throw new Error(
          `Range start ${rangeStart} exceeds end ${rangeEnd} in "${trimmed}"`
        );
      }

      baseValues = inclusiveRange(rangeStart, rangeEnd);
    } else {
      const value = integerWithinBounds(
        integerFromDigits(basePart, trimmed),
        bounds,
        trimmed
      );

      // N/S means: start at N, step forward through field max
      baseValues = stepStr !== undefined
        ? inclusiveRange(value, bounds.max)
        : [value];
    }
  }

  return stepStr !== undefined
    ? baseValues.filter((_, index) => index % step === 0)
    : baseValues;
}

function expandField(raw: string, bounds: FieldBounds): number[] {
  const tokens = raw.split(",");

  if (tokens.length === 0 || (tokens.length === 1 && tokens[0].trim().length === 0)) {
    throw new Error(`Encountered empty field expression`);
  }

  const accumulated = new Set<number>();

  for (const token of tokens) {
    const expanded = expandToken(token, bounds);
    if (expanded.length === 0) {
      throw new Error(
        `Token "${token}" produced no values — step may exceed the field range`
      );
    }
    for (const v of expanded) {
      accumulated.add(v);
    }
  }

  return [...accumulated].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new Error(
      `parseCron requires a string argument, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed.length === 0) {
    throw new Error(`parseCron received an empty expression`);
  }

  const rawFields = trimmed.split(/\s+/);

  if (rawFields.length !== 5) {
    throw new Error(
      `Cron expression requires exactly 5 whitespace-separated fields, ` +
      `found ${rawFields.length} in "${trimmed}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const bounds    = FIELD_BOUNDS[fieldName];
    const rawField  = rawFields[i];

    try {
      result[fieldName] = expandField(rawField, bounds);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Error in ${fieldName} field ("${rawField}"): ${message}`);
    }
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: Record<string, Primitive> = {}
): Record<string, Primitive> {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }
  for (const key of Object.keys(obj)) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];
    if (val !== null && typeof val === "object" && !Array.isArray(val))
      flattenObject(val as NestedObject, fullKey, result);
    else
      result[fullKey] = val as Primitive;
  }
  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      flattenObject(value as unknown as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_BOUNDS: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0, max: 59 },
  hour:       { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month:      { min: 1, max: 12 },
  dayOfWeek:  { min: 0, max: 6  },
};

const FIELD_ORDER: readonly CronField[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function integerFrom(raw: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Non-integer token: "${raw}"`);
  }
  const n = Number(trimmed);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer out of safe range: "${raw}"`);
  }
  return n;
}

function expandedRange(from: number, to: number, field: CronField): number[] {
  if (from > to) {
    throw new Error(
      `Range start ${from} exceeds end ${to} in field "${field}"`
    );
  }
  const result: number[] = [];
  for (let i = from; i <= to; i++) result.push(i);
  return result;
}

function steppedSequence(
  from: number,
  to: number,
  step: number,
  field: CronField
): number[] {
  if (from > to) {
    throw new Error(
      `Stepped range start ${from} exceeds end ${to} in field "${field}"`
    );
  }
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function resolvedToken(
  token: string,
  min: number,
  max: number,
  field: CronField
): number[] {
  const trimmed = token.trim();
  if (trimmed.length === 0) {
    throw new Error(`Empty token in field "${field}"`);
  }

  const slashIdx = trimmed.indexOf("/");
  if (slashIdx !== -1) {
    const basePart = trimmed.slice(0, slashIdx);
    const stepPart = trimmed.slice(slashIdx + 1);

    if (stepPart.includes("/")) {
      throw new Error(`Multiple slashes in token "${trimmed}" in field "${field}"`);
    }

    const step = integerFrom(stepPart);
    if (step === 0) {
      throw new Error(`Step value cannot be zero in field "${field}"`);
    }

    if (basePart === "*") {
      return steppedSequence(min, max, step, field);
    }

    const dashIdx = basePart.indexOf("-");
    if (dashIdx !== -1) {
      if (basePart.indexOf("-", dashIdx + 1) !== -1) {
        throw new Error(`Malformed range in token "${trimmed}" in field "${field}"`);
      }
      const rangeStart = integerFrom(basePart.slice(0, dashIdx));
      const rangeEnd   = integerFrom(basePart.slice(dashIdx + 1));
      return steppedSequence(rangeStart, rangeEnd, step, field);
    }

    const start = integerFrom(basePart);
    return steppedSequence(start, max, step, field);
  }

  if (trimmed === "*") {
    return expandedRange(min, max, field);
  }

  const dashIdx = trimmed.indexOf("-");
  if (dashIdx !== -1) {
    if (trimmed.indexOf("-", dashIdx + 1) !== -1) {
      throw new Error(`Malformed range token "${trimmed}" in field "${field}"`);
    }
    const rangeStart = integerFrom(trimmed.slice(0, dashIdx));
    const rangeEnd   = integerFrom(trimmed.slice(dashIdx + 1));
    return expandedRange(rangeStart, rangeEnd, field);
  }

  return [integerFrom(trimmed)];
}

function fieldValues(raw: string, field: CronField): number[] {
  const { min, max } = FIELD_BOUNDS[field];

  if (raw.trim().length === 0) {
    throw new Error(`Empty field expression for "${field}"`);
  }

  const segments = raw.split(",");
  const accumulated = new Set<number>();

  for (const segment of segments) {
    if (segment.trim().length === 0) {
      throw new Error(
        `Empty segment (trailing or double comma?) in field "${field}": "${raw}"`
      );
    }

    const values = resolvedToken(segment, min, max, field);

    for (const v of values) {
      if (v < min || v > max) {
        throw new RangeError(
          `Value ${v} is out of bounds [${min}–${max}] for field "${field}"`
        );
      }
      accumulated.add(v);
    }
  }

  if (accumulated.size === 0) {
    throw new Error(`No values could be resolved for field "${field}"`);
  }

  return Array.from(accumulated).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(
      `Cron expression must be a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error("Cron expression must not be empty or blank");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 whitespace-separated fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as ParsedCron;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    // parts[i] is guaranteed defined: length === 5 and FIELD_ORDER.length === 5
    result[field] = fieldValues(parts[i]!, field);
  }

  return result;
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function unique(values: number[]): number[] {
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  if (segment === "*") return range(min, max);

  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${stepStr}`);
    const start = base === "*" ? min : parseInt(base, 10);
    if (isNaN(start)) throw new Error(`Invalid step base: ${base}`);
    const result: number[] = [];
    for (let i = start; i <= max; i += step) result.push(i);
    return result;
  }

  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${segment}`);
    if (start > end) throw new Error(`Range start > end: ${segment}`);
    return range(start, end);
  }

  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value: ${segment}`);
  return [value];
}

function parseField(field: string, fieldName: FieldName): number[] {
  const { min, max } = FIELD_RANGES[fieldName];

  const values = field
    .split(",")
    .flatMap((segment) => parseSegment(segment.trim(), min, max));

  const result = unique(values);

  const outOfRange = result.filter((v) => v < min || v > max);
  if (outOfRange.length > 0) {
    throw new Error(
      `Values out of range for ${fieldName} (${min}-${max}): ${outOfRange.join(", ")}`
    );
  }

  return result;
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  const dayOfWeekRaw = parseField(dowField, "dayOfWeek");
  const dayOfWeek = unique(
    dayOfWeekRaw.map((v) => (v === 7 ? 0 : v))
  );

  return {
    minute: parseField(minuteField, "minute"),
    hour: parseField(hourField, "hour"),
    dayOfMonth: parseField(domField, "dayOfMonth"),
    month: parseField(monthField, "month"),
    dayOfWeek,
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: Record<string, Primitive> = {}
): Record<string, Primitive> {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }
  const keys = Object.keys(obj);
  if (keys.length === 0 && prefix) {
    result[prefix] = undefined;
    return result;
  }
  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;
    const newKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];
    val !== null && typeof val === "object" && !Array.isArray(val)
      ? flattenObject(val as NestedObject, newKey, result)
      : (result[newKey] = val as Primitive);
  }
  return result;
}

type CronResult = { minute: number[]; hour: number[]; dayOfMonth: number[]; month: number[]; dayOfWeek: number[] };

function parseField(field: string, min: number, max: number): number[] {
  const expand = (lo: number, hi: number, step = 1): number[] => {
    if (lo < min || hi > max || step < 1) throw new Error(`Value out of range [${min}-${max}]: ${lo}-${hi}`);
    const r: number[] = [];
    for (let i = lo; i <= hi; i += step) r.push(i);
    return r;
  };

  if (field.includes(",")) return [...new Set(field.split(",").flatMap(f => parseField(f, min, max)))].sort((a, b) => a - b);
  if (field.startsWith("*/")) { const s = parseInt(field.slice(2)); if (isNaN(s)) throw new Error(`Bad step: ${field}`); return expand(min, max, s); }
  if (field === "*") return expand(min, max);
  if (field.includes("-")) {
    const [a, b] = field.split("-").map(Number);
    if (isNaN(a) || isNaN(b) || a > b) throw new Error(`Bad range: ${field}`);
    return expand(a, b);
  }
  const n = parseInt(field, 10);
  if (isNaN(n) || String(n) !== field.trim() || n < min || n > max) throw new Error(`Invalid value: "${field}" for range [${min}-${max}]`);
  return [n];
}

export default function parseCron(expr: string): CronResult {
  if (!expr || typeof expr !== "string") throw new Error("Expression must be a non-empty string");
  const fields = expr.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);
  const [[minute], [hour], [dayOfMonth], [month], [dayOfWeek]] = (
    [[fields[0], 0, 59], [fields[1], 0, 23], [fields[2], 1, 31], [fields[3], 1, 12], [fields[4], 0, 6]] as [string, number, number][]
  ).map(([f, mn, mx]) => [parseField(f, mn, mx)]);
  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

type CronResult = { minute: number[]; hour: number[]; dayOfMonth: number[]; month: number[]; dayOfWeek: number[] };

const FIELDS: [keyof CronResult, number, number][] = [
  ["minute", 0, 59], ["hour", 0, 23], ["dayOfMonth", 1, 31], ["month", 1, 12], ["dayOfWeek", 0, 6],
];

const range = (a: number, b: number) => Array.from({ length: b - a + 1 }, (_, i) => a + i);

function parseField(expr: string, min: number, max: number): number[] {
  if (expr === "*") return range(min, max);

  if (expr.includes(","))
    return [...new Set(expr.split(",").flatMap(e => parseField(e, min, max)))].sort((a, b) => a - b);

  if (expr.startsWith("*/")) {
    const step = +expr.slice(2);
    if (!step || step < 1) throw new Error(`Invalid step: ${expr}`);
    return range(min, max).filter(v => (v - min) % step === 0);
  }

  if (expr.includes("-")) {
    const [a, b] = expr.split("-").map(Number);
    if (isNaN(a) || isNaN(b) || a < min || b > max || a > b) throw new Error(`Invalid range: ${expr}`);
    return range(a, b);
  }

  const n = +expr;
  if (!Number.isInteger(n) || n < min || n > max) throw new Error(`Out of range [${min}-${max}]: ${expr}`);
  return [n];
}

export default function parseCron(cron: string): CronResult {
  const parts = cron.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);
  return Object.fromEntries(FIELDS.map(([name, min, max], i) => [name, parseField(parts[i], min, max)])) as CronResult;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type CronResult = { minute: number[]; hour: number[]; dayOfMonth: number[]; month: number[]; dayOfWeek: number[] };

const RANGES = { minute: [0,59], hour: [0,23], dayOfMonth: [1,31], month: [1,12], dayOfWeek: [0,7] } as const;

function parseField(field: string, [min, max]: readonly [number, number]): number[] {
  const expand = (lo: number, hi: number, step = 1) => {
    if (lo < min || hi > max || lo > hi || step < 1) throw new Error(`Out of range: ${lo}-${hi}/${step}`);
    return Array.from({ length: Math.floor((hi - lo) / step) + 1 }, (_, i) => lo + i * step);
  };
  if (field.includes(",")) return [...new Set(field.split(",").flatMap(f => parseField(f, [min, max])))].sort((a,b)=>a-b);
  if (field.startsWith("*/")) return expand(min, max, +field.slice(2));
  if (field.includes("/")) { const [r,s]=field.split("/"); const [lo,hi]=r.split("-").map(Number); return expand(lo,hi,+s); }
  if (field.includes("-")) { const [lo,hi]=field.split("-").map(Number); return expand(lo,hi); }
  if (field === "*") return expand(min, max);
  const n = +field;
  if (!Number.isInteger(n) || n < min || n > max) throw new Error(`Invalid value: ${field}`);
  return [n];
}

export default function parseCron(expr: string): CronResult {
  const parts = expr.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);
  const [minute, hour, dayOfMonth, month, dayOfWeek] = (Object.keys(RANGES) as (keyof typeof RANGES)[])
    .map((k, i) => parseField(parts[i], RANGES[k]));
  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, min: number, max: number): number[] => {
  if (field === "*") return range(min, max);

  if (field.includes(",")) {
    return [...new Set(
      field.split(",").flatMap(part => parseField(part.trim(), min, max))
    )].sort((a, b) => a - b);
  }

  if (field.includes("/")) {
    const [rangeStr, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: "${stepStr}"`);

    const [start, end] = rangeStr === "*"
      ? [min, max]
      : (() => {
          const [s, e] = rangeStr.split("-").map(Number);
          if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range in step: "${rangeStr}"`);
          return [s, e ?? s];
        })();

    const values: number[] = [];
    for (let v = start; v <= end; v += step) values.push(v);
    return values.filter(v => v >= min && v <= max);
  }

  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: "${field}"`);
    if (start > end) throw new Error(`Range start ${start} > end ${end}`);
    if (start < min || end > max) throw new Error(`Range "${field}" out of bounds [${min}, ${max}]`);
    return range(start, end);
  }

  const num = parseInt(field, 10);
  if (isNaN(num)) throw new Error(`Invalid cron value: "${field}"`);
  if (num < min || num > max) throw new Error(`Value ${num} out of bounds [${min}, ${max}]`);
  return [num];
};

const parseCron = (expression: string): CronFields => {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = parts;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const fieldStrings = [minuteStr, hourStr, domStr, monthStr, dowStr];

  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      result[name] = parseField(fieldStrings[i], min, max);
    } catch (err) {
      throw new Error(`Invalid cron field "${name}" with value "${fieldStrings[i]}": ${(err as Error).message}`);
    }
  }

  return result;
};

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(obj: NestedObject, prefix = ""): FlatObject {
  return Object.entries(obj).reduce<FlatObject>((acc, [key, value]) => {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
      Object.assign(acc, flattenObject(value as NestedObject, fullKey));
    } else {
      acc[fullKey] = value as Primitive | Array<unknown>;
    }
    return acc;
  }, {});
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_BOUNDS: Record<CronField, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function intFromString(raw: string, fieldName: CronField): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Expected integer, got "${raw}" in field "${fieldName}"`);
  }
  return parseInt(raw, 10);
}

function numbersInSteppedRange(
  start: number,
  end: number,
  step: number,
  bounds: FieldRange,
  fieldName: CronField,
): number[] {
  if (step < 1) {
    throw new Error(`Step must be at least 1, got ${step} in field "${fieldName}"`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} exceeds end ${end} in field "${fieldName}"`);
  }
  if (start < bounds.min || end > bounds.max) {
    throw new Error(
      `Range ${start}-${end} outside allowed bounds [${bounds.min}, ${bounds.max}] in field "${fieldName}"`,
    );
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function tokenToNumbers(token: string, bounds: FieldRange, fieldName: CronField): number[] {
  const slashAt = token.indexOf("/");

  if (slashAt !== -1) {
    const baseToken = token.slice(0, slashAt);
    const stepToken = token.slice(slashAt + 1);

    if (!/^\d+$/.test(stepToken)) {
      throw new Error(`Non-integer step "${stepToken}" in field "${fieldName}"`);
    }
    const step = parseInt(stepToken, 10);
    if (step < 1) {
      throw new Error(`Step must be at least 1, got ${step} in field "${fieldName}"`);
    }

    if (baseToken === "*") {
      return numbersInSteppedRange(bounds.min, bounds.max, step, bounds, fieldName);
    }

    const dashAt = baseToken.indexOf("-");
    if (dashAt !== -1) {
      const start = intFromString(baseToken.slice(0, dashAt), fieldName);
      const end = intFromString(baseToken.slice(dashAt + 1), fieldName);
      return numbersInSteppedRange(start, end, step, bounds, fieldName);
    }

    const start = intFromString(baseToken, fieldName);
    if (start < bounds.min || start > bounds.max) {
      throw new Error(
        `Value ${start} outside allowed bounds [${bounds.min}, ${bounds.max}] in field "${fieldName}"`,
      );
    }
    return numbersInSteppedRange(start, bounds.max, step, bounds, fieldName);
  }

  if (token === "*") {
    return numbersInSteppedRange(bounds.min, bounds.max, 1, bounds, fieldName);
  }

  const dashAt = token.indexOf("-");
  if (dashAt !== -1) {
    const start = intFromString(token.slice(0, dashAt), fieldName);
    const end = intFromString(token.slice(dashAt + 1), fieldName);
    return numbersInSteppedRange(start, end, 1, bounds, fieldName);
  }

  const value = intFromString(token, fieldName);
  if (value < bounds.min || value > bounds.max) {
    throw new Error(
      `Value ${value} outside allowed bounds [${bounds.min}, ${bounds.max}] in field "${fieldName}"`,
    );
  }
  return [value];
}

function fieldToNumbers(rawField: string, fieldName: CronField): number[] {
  const bounds = FIELD_BOUNDS[fieldName];
  const tokens = rawField.split(",");

  const accumulated = new Set<number>();
  for (const token of tokens) {
    const trimmedToken = token.trim();
    if (trimmedToken === "") {
      throw new Error(`Empty token in field "${fieldName}": "${rawField}"`);
    }
    for (const n of tokenToNumbers(trimmedToken, bounds, fieldName)) {
      accumulated.add(n);
    }
  }

  return Array.from(accumulated).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron received ${typeof expression}, expected string`);
  }

  const trimmedExpression = expression.trim();
  if (trimmedExpression.length === 0) {
    throw new Error("parseCron received an empty expression");
  }

  const rawFields = trimmedExpression.split(/\s+/);
  if (rawFields.length !== 5) {
    throw new Error(
      `parseCron expected 5 fields but received ${rawFields.length}: "${expression}"`,
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = rawFields;

  return {
    minute:     fieldToNumbers(minuteRaw, "minute"),
    hour:       fieldToNumbers(hourRaw,   "hour"),
    dayOfMonth: fieldToNumbers(domRaw,    "dayOfMonth"),
    month:      fieldToNumbers(monthRaw,  "month"),
    dayOfWeek:  fieldToNumbers(dowRaw,    "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: Record<string, Primitive> = {}
): Record<string, Primitive> {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }
  const keys = Object.keys(obj);
  if (keys.length === 0 && prefix) {
    result[prefix] = {} as unknown as Primitive;
    return result;
  }
  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;
    flattenObject(obj[key] as NestedObject, prefix ? `${prefix}.${key}` : key, result);
  }
  return result;
}

type NestedObject = { [key: string]: unknown };
type FlatRecord = Record<string, unknown>;

const isPlainObject = (value: unknown): value is NestedObject => {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
};

const flattenInto = (
  obj: NestedObject,
  prefix: string,
  ancestorRefs: WeakSet<object>,
  output: FlatRecord
): void => {
  if (ancestorRefs.has(obj)) return;

  ancestorRefs.add(obj);

  const ownKeys = Object.keys(obj);

  if (ownKeys.length === 0) {
    if (prefix.length > 0) {
      output[prefix] = obj;
    }
    ancestorRefs.delete(obj);
    return;
  }

  for (const key of ownKeys) {
    const composedKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (isPlainObject(value)) {
      flattenInto(value, composedKey, ancestorRefs, output);
    } else {
      output[composedKey] = value;
    }
  }

  ancestorRefs.delete(obj);
};

