  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject requires a plain object, received: ${obj === null ? "null" : typeof obj}`
    );
  }

  const output: FlatRecord = {};
  flattenInto(obj, "", new WeakSet(), output);
  return output;
};

