type NestedObject = Record<string, unknown>;

const isPlainObject = (value: unknown): value is NestedObject =>
  value !== null &&
  typeof value === "object" &&
  !Array.isArray(value) &&
  (Object.getPrototypeOf(value) === Object.prototype ||
    Object.getPrototypeOf(value) === null);

const accumulateFlatEntries = (
  input: NestedObject,
  prefix: string,
  ancestorRefs: WeakSet<object>,
  accumulator: NestedObject
): void => {
  if (ancestorRefs.has(input)) {
    throw new TypeError(
      `Circular reference encountered at path: "${prefix || "(root)"}"`
    );
  }

  ancestorRefs.add(input);

  const ownKeys = Object.keys(input);

  if (ownKeys.length === 0) {
    if (prefix !== "") {
      accumulator[prefix] = input;
    }
    ancestorRefs.delete(input);
    return;
  }

  for (const key of ownKeys) {
    const value = input[key];
    const composedKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      accumulateFlatEntries(value, composedKey, ancestorRefs, accumulator);
    } else {
      accumulator[composedKey] = value;
    }
  }

  ancestorRefs.delete(input);
};

