  if (!isPlainObject(input)) {
    throw new TypeError(
      `Expected a plain object, received: ${
        input === null ? "null" : Array.isArray(input) ? "array" : typeof input
      }`
    );
  }

  const accumulator: NestedObject = {};
  accumulateFlatEntries(input, "", new WeakSet<object>(), accumulator);
  return accumulator;
}

