interface CronParsed {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronParsed, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const clamp = (value: number, min: number, max: number): number =>
  Math.max(min, Math.min(max, value));

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, min: number, max: number): number[] => {
  if (field === "*") {
    return range(min, max);
  }

  if (field.includes(",")) {
    return field
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (field.includes("/")) {
    const [rangepart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let rangeStart = min;
    let rangeEnd = max;

    if (rangepart !== "*") {
      if (rangepart.includes("-")) {
        const [startStr, endStr] = rangepart.split("-");
        rangeStart = clamp(parseInt(startStr, 10), min, max);
        rangeEnd = clamp(parseInt(endStr, 10), min, max);
      } else {
        rangeStart = clamp(parseInt(rangepart, 10), min, max);
      }
    }

    const values: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      values.push(i);
    }
    return values;
  }

  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${field}`);
    }

    const clamped_start = clamp(start, min, max);
    const clamped_end = clamp(end, min, max);

    if (clamped_start > clamped_end) {
      throw new Error(`Invalid range: start ${start} > end ${end}`);
    }

    return range(clamped_start, clamped_end);
  }

  const value = parseInt(field, 10);

  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: ${field}`);
  }

  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  }

  return [value];
};

