    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const fieldKeys = Object.keys(FIELD_RANGES) as (keyof CronParsed)[];
  const fieldValues = [minuteField, hourField, domField, monthField, dowField];

  const result = {} as CronParsed;

  for (let i = 0; i < fieldKeys.length; i++) {
    const key = fieldKeys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(fieldValues[i], min, max);
  }

  return result;
};

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: Record<string, Primitive> = {}
): Record<string, Primitive> {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }
  const keys = Object.keys(obj);
  if (keys.length === 0 && prefix) {
    result[prefix] = {} as unknown as Primitive;
    return result;
  }
  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;
    const newKey = prefix ? `${prefix}.${key}` : key;
    flattenObject(obj[key] as NestedObject, newKey, result);
  }
  return result;
}

export interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronResult;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 6  },
] as const;

const DIGITS_RE = /^\d+$/;

function assertInRange(value: number, config: FieldConfig): void {
  // dayOfWeek: many cron implementations accept 7 as a Sunday alias
  const effectiveMax = config.name === "dayOfWeek" ? 7 : config.max;
  if (!Number.isFinite(value) || value < config.min || value > effectiveMax) {
    throw new RangeError(
      `Value ${value} is out of valid range [${config.min}–${effectiveMax}] for field "${config.name}"`
    );
  }
}

function normalizeValue(value: number, config: FieldConfig): number {
  return config.name === "dayOfWeek" && value === 7 ? 0 : value;
}

function expandRange(
  start: number,
  end: number,
  step: number,
  config: FieldConfig
): number[] {
  if (step <= 0) {
    throw new RangeError(
      `Step must be a positive integer in field "${config.name}", got ${step}`
    );
  }
  if (start > end) {
    throw new RangeError(
      `Range start (${start}) must not exceed end (${end}) in field "${config.name}"`
    );
  }
  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(normalizeValue(v, config));
  }
  return values;
}

function parseSegment(raw: string, config: FieldConfig): number[] {
  const expr = raw.trim();

  if (expr.length === 0) {
    throw new SyntaxError(`Empty segment in field "${config.name}"`);
  }

  // --- Step: */n  |  a-b/n  |  a/n ---
  const slashIdx = expr.indexOf("/");
  if (slashIdx !== -1) {
    const left  = expr.slice(0, slashIdx);
    const right = expr.slice(slashIdx + 1);

    if (!DIGITS_RE.test(right)) {
      throw new SyntaxError(
        `Invalid step value "${right}" in field "${config.name}" — must be a non-negative integer`
      );
    }
    const step = parseInt(right, 10);
    if (step === 0) {
      throw new RangeError(`Step of 0 would produce an infinite loop in field "${config.name}"`);
    }

    // */step
    if (left === "*") {
      return expandRange(config.min, config.max, step, config);
    }

    // a-b/step
    if (left.includes("-")) {
      const dashIdx  = left.indexOf("-");
      const startStr = left.slice(0, dashIdx);
      const endStr   = left.slice(dashIdx + 1);
      if (!DIGITS_RE.test(startStr) || !DIGITS_RE.test(endStr)) {
        throw new SyntaxError(`Invalid range "${left}" in field "${config.name}"`);
      }
      const start = parseInt(startStr, 10);
      const end   = parseInt(endStr,   10);
      assertInRange(start, config);
      assertInRange(end,   config);
      return expandRange(start, end, step, config);
    }

    // a/step — start from a, go to field max
    if (DIGITS_RE.test(left)) {
      const start = parseInt(left, 10);
      assertInRange(start, config);
      return expandRange(start, config.max, step, config);
    }

    throw new SyntaxError(`Unexpected step expression "${expr}" in field "${config.name}"`);
  }

  // --- Wildcard ---
  if (expr === "*") {
    return expandRange(config.min, config.max, 1, config);
  }

  // --- Range: a-b ---
  const dashIdx = expr.indexOf("-");
  if (dashIdx !== -1) {
    const startStr = expr.slice(0, dashIdx);
    const endStr   = expr.slice(dashIdx + 1);
    if (!DIGITS_RE.test(startStr) || !DIGITS_RE.test(endStr)) {
      throw new SyntaxError(
        `Invalid range "${expr}" in field "${config.name}" — both bounds must be non-negative integers`
      );
    }
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    assertInRange(start, config);
    assertInRange(end,   config);
    return expandRange(start, end, 1, config);
  }

  // --- Single number ---
  if (DIGITS_RE.test(expr)) {
    const value = parseInt(expr, 10);
    assertInRange(value, config);
    return [normalizeValue(value, config)];
  }

  throw new SyntaxError(
    `Unrecognized expression "${expr}" in field "${config.name}"`
  );
}

function parseField(expr: string, config: FieldConfig): number[] {
  if (!expr || expr.trim().length === 0) {
    throw new SyntaxError(`Field "${config.name}" expression is empty`);
  }

  const segments = expr.split(",");
  const seen     = new Set<number>();
  const values: number[] = [];

  for (const segment of segments) {
    if (segment.trim().length === 0) {
      throw new SyntaxError(
        `Empty item in comma-separated list for field "${config.name}" — trailing/leading commas are not allowed`
      );
    }
    for (const v of parseSegment(segment, config)) {
      if (!seen.has(v)) {
        seen.add(v);
        values.push(v);
      }
    }
  }

  return values.sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expected a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 space-separated fields, got ${fields.length}: "${expression}"`
    );
  }

  return {
    minute:     parseField(fields[0], FIELD_CONFIGS[0]),
    hour:       parseField(fields[1], FIELD_CONFIGS[1]),
    dayOfMonth: parseField(fields[2], FIELD_CONFIGS[2]),
    month:      parseField(fields[3], FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(fields[4], FIELD_CONFIGS[4]),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldSpec {
  readonly name: keyof ParsedCron;
  readonly min: number;
  readonly max: number;
}

const FIELD_SPECS: readonly FieldSpec[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 7  }, // 7 is a Sunday alias, normalized to 0
] as const;

function buildRange(start: number, end: number, step: number, context: string): number[] {
  if (!Number.isInteger(step) || step <= 0) {
    throw new RangeError(`Step must be a positive integer in "${context}", got: ${step}`);
  }
  if (!Number.isInteger(start) || !Number.isInteger(end)) {
    throw new TypeError(`Range bounds must be integers in "${context}"`);
  }
  if (start > end) {
    throw new RangeError(`Range start (${start}) exceeds end (${end}) in "${context}"`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseToken(token: string, spec: FieldSpec): number[] {
  if (token.length === 0) {
    throw new TypeError(`Empty token encountered for field "${spec.name}"`);
  }

  // Step expression: */n  |  start/n  |  start-end/n
  const slashIndex = token.indexOf("/");
  if (slashIndex !== -1) {
    const prefix = token.slice(0, slashIndex);
    const stepRaw = token.slice(slashIndex + 1);
    const step = Number(stepRaw);
    if (!Number.isInteger(step) || step <= 0) {
      throw new TypeError(`Invalid step "${stepRaw}" in expression "${token}"`);
    }
    if (prefix === "*") {
      return buildRange(spec.min, spec.max, step, token);
    }
    const dashIndex = prefix.indexOf("-");
    if (dashIndex > 0) {
      const start = Number(prefix.slice(0, dashIndex));
      const end = Number(prefix.slice(dashIndex + 1));
      if (!Number.isInteger(start) || !Number.isInteger(end)) {
        throw new TypeError(`Invalid range "${prefix}" in step expression "${token}"`);
      }
      return buildRange(start, end, step, token);
    }
    const start = Number(prefix);
    if (!Number.isInteger(start)) {
      throw new TypeError(`Invalid start value "${prefix}" in step expression "${token}"`);
    }
    return buildRange(start, spec.max, step, token);
  }

  // Wildcard
  if (token === "*") {
    return buildRange(spec.min, spec.max, 1, token);
  }

  // Range: start-end (leading dash would mean negative, which is invalid)
  const dashIndex = token.indexOf("-");
  if (dashIndex > 0) {
    const start = Number(token.slice(0, dashIndex));
    const end = Number(token.slice(dashIndex + 1));
    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new TypeError(`Invalid range values in "${token}"`);
    }
    return buildRange(start, end, 1, token);
  }

  // Single integer value
  const value = Number(token);
  if (!Number.isInteger(value) || value < 0) {
    throw new TypeError(
      `Invalid cron value "${token}" — expected a non-negative integer`
    );
  }
  return [value];
}

function parseField(raw: string, spec: FieldSpec): number[] {
  if (!raw || raw.trim().length === 0) {
    throw new TypeError(`Field "${spec.name}" is empty`);
  }

  const parts = raw.split(",");
  if (parts.some((p) => p.trim().length === 0)) {
    throw new TypeError(
      `Malformed comma-separated list for field "${spec.name}": "${raw}"`
    );
  }

  const collected = new Set<number>();
  for (const part of parts) {
    for (const v of parseToken(part.trim(), spec)) {
      collected.add(v);
    }
  }

  // Validate bounds and normalize (dayOfWeek: 7 → 0 per POSIX convention)
  const effectiveMax = spec.name === "dayOfWeek" ? 6 : spec.max;
  const normalized = new Set<number>();

  for (const v of collected) {
    if (spec.name === "dayOfWeek" && v === 7) {
      normalized.add(0);
      continue;
    }
    if (v < spec.min || v > effectiveMax) {
      throw new RangeError(
        `Value ${v} is out of the valid range [${spec.min}–${effectiveMax}] for field "${spec.name}"`
      );
    }
    normalized.add(v);
  }

  if (normalized.size === 0) {
    throw new RangeError(`Field "${spec.name}" produced no valid values from "${raw}"`);
  }

  return Array.from(normalized).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string argument, received: ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new TypeError("parseCron received an empty or whitespace-only expression");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new RangeError(
      `Cron expression must have exactly 5 space-separated fields; ` +
        `got ${fields.length} in: "${expression}"`
    );
  }

  const result = {} as ParsedCron;
  for (let i = 0; i < FIELD_SPECS.length; i++) {
    const spec = FIELD_SPECS[i];
    result[spec.name] = parseField(fields[i], spec);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_BOUNDS: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: readonly CronField[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function integerFromRawString(raw: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Expected an integer, got: "${raw}"`);
  }
  const n = parseInt(raw, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer overflows safe range: "${raw}"`);
  }
  return n;
}

function integerSequence(from: number, to: number, by: number): number[] {
  if (by <= 0) {
    throw new Error(`Step must be a positive integer, got: ${by}`);
  }
  if (from > to) {
    throw new Error(`Range start ${from} exceeds range end ${to}`);
  }
  const result: number[] = [];
  for (let i = from; i <= to; i += by) {
    result.push(i);
  }
  return result;
}

function boundsClampedValues(
  values: number[],
  min: number,
  max: number,
  field: CronField,
): number[] {
  for (const v of values) {
    if (v < min || v > max) {
      throw new Error(
        `Value ${v} is outside valid range [${min}, ${max}] for field "${field}"`,
      );
    }
  }
  return values;
}

function tokenToIntegers(
  token: string,
  fieldMin: number,
  fieldMax: number,
): number[] {
  if (token === "") {
    throw new Error("Empty token encountered");
  }

  const slashAt = token.indexOf("/");

  if (slashAt !== -1) {
    const stepRaw = token.slice(slashAt + 1);
    const baseRaw = token.slice(0, slashAt);

    if (stepRaw === "") {
      throw new Error(`Missing step value after "/" in: "${token}"`);
    }
    if (baseRaw === "") {
      throw new Error(`Missing base before "/" in: "${token}"`);
    }

    const step = integerFromRawString(stepRaw);
    if (step <= 0) {
      throw new Error(`Step must be positive, got: ${step}`);
    }

    if (baseRaw === "*") {
      return integerSequence(fieldMin, fieldMax, step);
    }

    const dashAt = baseRaw.indexOf("-");
    if (dashAt !== -1) {
      const rangeStart = integerFromRawString(baseRaw.slice(0, dashAt));
      const rangeEnd   = integerFromRawString(baseRaw.slice(dashAt + 1));
      return integerSequence(rangeStart, rangeEnd, step);
    }

    const singleStart = integerFromRawString(baseRaw);
    return integerSequence(singleStart, fieldMax, step);
  }

  if (token === "*") {
    return integerSequence(fieldMin, fieldMax, 1);
  }

  const dashAt = token.indexOf("-");
  if (dashAt !== -1) {
    if (dashAt === 0) {
      throw new Error(`Range token starts with "-": "${token}"`);
    }
    const rangeStart = integerFromRawString(token.slice(0, dashAt));
    const rangeEndRaw = token.slice(dashAt + 1);
    if (rangeEndRaw === "") {
      throw new Error(`Range token missing end value: "${token}"`);
    }
    const rangeEnd = integerFromRawString(rangeEndRaw);
    return integerSequence(rangeStart, rangeEnd, 1);
  }

  return [integerFromRawString(token)];
}

function fieldToSortedIntegers(raw: string, field: CronField): number[] {
  const { min, max } = FIELD_BOUNDS[field];

  if (raw === "" || raw.trim() === "") {
    throw new Error(`Empty expression for field "${field}"`);
  }

  const parts = raw.split(",");
  const accumulated = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new Error(
        `Empty segment in comma-separated list for field "${field}"`,
      );
    }
    const expanded = tokenToIntegers(trimmed, min, max);
    const bounded  = boundsClampedValues(expanded, min, max, field);
    for (const v of bounded) {
      accumulated.add(v);
    }
  }

  return Array.from(accumulated).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new Error(`parseCron requires a string, got: ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const segments = trimmed.split(/\s+/);
  if (segments.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${segments.length}: "${expression}"`,
    );
  }

  const [minuteRaw, hourRaw, dayOfMonthRaw, monthRaw, dayOfWeekRaw] = segments;

  return {
    minute:     fieldToSortedIntegers(minuteRaw,     "minute"),
    hour:       fieldToSortedIntegers(hourRaw,        "hour"),
    dayOfMonth: fieldToSortedIntegers(dayOfMonthRaw,  "dayOfMonth"),
    month:      fieldToSortedIntegers(monthRaw,        "month"),
    dayOfWeek:  fieldToSortedIntegers(dayOfWeekRaw,   "dayOfWeek"),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(from: number, to: number): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i++) result.push(i);
  return result;
}

function parseField(expr: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of expr.split(",")) {
    if (part === "*") {
      range(min, max).forEach((v) => values.add(v));
    } else if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${part}`);
      for (let v = min; v <= max; v += step) values.add(v);
    } else if (part.includes("/")) {
      const [rangePart, stepPart] = part.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${part}`);
      const [fromStr, toStr] = rangePart.split("-");
      const from = parseInt(fromStr, 10);
      const to = toStr !== undefined ? parseInt(toStr, 10) : max;
      if (isNaN(from) || isNaN(to)) throw new Error(`Invalid range: ${part}`);
      for (let v = from; v <= to; v += step) values.add(v);
    } else if (part.includes("-")) {
      const [fromStr, toStr] = part.split("-");
      const from = parseInt(fromStr, 10);
      const to = parseInt(toStr, 10);
      if (isNaN(from) || isNaN(to)) throw new Error(`Invalid range: ${part}`);
      if (from > to) throw new Error(`Range start exceeds end: ${part}`);
      range(from, to).forEach((v) => values.add(v));
    } else {
      const num = parseInt(part, 10);
      if (isNaN(num)) throw new Error(`Invalid value: ${part}`);
      values.add(num);
    }
  }

  const sorted = [...values].sort((a, b) => a - b);

  for (const v of sorted) {
    if (v < min || v > max) {
      throw new Error(`Value ${v} out of range [${min}, ${max}]`);
    }
  }

  return sorted;
}

export default function parseCron(expression: string): CronFields {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  const result = {} as CronFields;
  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(exprs[i], min, max);
  }

  return result;
}

type NestedRecord = { [key: string]: unknown };

const isNonEmptyPlainObject = (value: unknown): value is NestedRecord => {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  if (proto !== Object.prototype && proto !== null) return false;
  return Object.keys(value as NestedRecord).length > 0;
};

const buildFlatEntries = (
  source: NestedRecord,
  prefix: string,
  accumulator: Record<string, unknown>,
  ancestors: WeakSet<object>
): void => {
  // Circular reference — stop descending this path, drop the offending key entirely
  if (ancestors.has(source)) return;
  ancestors.add(source);

  for (const [key, value] of Object.entries(source)) {
    const dotKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    if (isNonEmptyPlainObject(value)) {
      buildFlatEntries(value, dotKey, accumulator, ancestors);
    } else {
      // null, undefined, primitives, arrays, Dates, RegExps, empty {} — all become leaves
      accumulator[dotKey] = value;
    }
  }

  // Remove from ancestors so the same object may appear on a separate, non-circular branch
  ancestors.delete(source);
};

export default function flattenObject(
  input: Record<string, unknown>
): Record<string, unknown> {
  if (input === null || typeof input !== "object") return {};

  const result: Record<string, unknown> = {};
  buildFlatEntries(input as NestedRecord, "", result, new WeakSet<object>());
  return result;
}

type Primitive = string | number | boolean | bigint | null | undefined;
type FlatObject = Record<string, Primitive>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function _flatten(
  obj: Record<string, unknown>,
  prefix: string,
  result: FlatObject,
  seen: WeakSet<object>
): void {
  if (seen.has(obj)) {
    throw new Error(
      `Circular reference detected at key "${prefix || "<root>"}"`
    );
  }

  seen.add(obj);

  for (const key of Object.keys(obj)) {
    if (key === "") continue; // skip empty-string keys — they produce ambiguous "a..b" paths

    const fullKey = prefix === "" ? key : `${prefix}.${key}`;
    const value = obj[key];

    if (isPlainObject(value)) {
      // Recurse into plain objects; empty objects produce no keys (no leaf to write)
      _flatten(value, fullKey, result, seen);
    } else {
      // Arrays, Dates, RegExps, Maps, Sets, functions, primitives — all become leaves
      result[fullKey] = value as Primitive;
    }
  }

  // Remove after processing so the same reference in a sibling branch isn't a false positive
  seen.delete(obj);
}

function flattenObject(obj: unknown): FlatObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: FlatObject = {};
  _flatten(obj, "", result, new WeakSet());
  return result;
}

export default flattenObject;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(expr: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of expr.split(",")) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    if (trimmed.startsWith("*/")) {
      const step = parseInt(trimmed.slice(2), 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: "${trimmed}"`);
      }
      for (let i = min; i <= max; i += step) results.add(i);
      continue;
    }

    if (trimmed.includes("/")) {
      const [rangePart, stepPart] = trimmed.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: "${trimmed}"`);
      }
      const [rangeMin, rangeMax] = parseRange(rangePart, min, max);
      for (let i = rangeMin; i <= rangeMax; i += step) results.add(i);
      continue;
    }

    if (trimmed.includes("-")) {
      const [rangeMin, rangeMax] = parseRange(trimmed, min, max);
      for (let i = rangeMin; i <= rangeMax; i++) results.add(i);
      continue;
    }

    const value = parseInt(trimmed, 10);
    if (isNaN(value)) {
      throw new Error(`Invalid cron field value: "${trimmed}"`);
    }
    if (value < min || value > max) {
      throw new Error(`Value ${value} out of range [${min}, ${max}]`);
    }
    results.add(value);
  }

  return Array.from(results).sort((a, b) => a - b);
}

function parseRange(expr: string, min: number, max: number): [number, number] {
  const [startStr, endStr] = expr.split("-");
  const start = parseInt(startStr, 10);
  const end = parseInt(endStr, 10);

  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Invalid range: "${expr}"`);
  }
  if (start < min || start > max) {
    throw new Error(`Range start ${start} out of range [${min}, ${max}]`);
  }
  if (end < min || end > max) {
    throw new Error(`Range end ${end} out of range [${min}, ${max}]`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} is greater than end ${end}`);
  }

  return [start, end];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] =
    fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const exprs = [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr];

  const result = {} as CronResult;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      result[name] = parseField(exprs[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid "${name}" field ("${exprs[i]}"): ${(err as Error).message}`
      );
    }
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

export type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_BOUNDS: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function integerFromToken(raw: string, location: string): number {
  const trimmed = raw.trim();
  if (trimmed.length === 0 || !/^\d+$/.test(trimmed)) {
    throw new Error(`Expected non-negative integer at ${location}, received: "${raw}"`);
  }
  const n = Number(trimmed);
  if (!Number.isInteger(n) || !Number.isFinite(n)) {
    throw new Error(`Non-finite integer at ${location}: "${raw}"`);
  }
  return n;
}

function throwIfOutOfBounds(value: number, min: number, max: number, location: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} falls outside [${min}, ${max}] at ${location}`
    );
  }
}

function expandedSteppedRange(
  start: number,
  end: number,
  step: number,
  min: number,
  max: number,
  location: string
): number[] {
  if (step <= 0) {
    throw new Error(`Step must be a positive integer at ${location}, received ${step}`);
  }
  if (start > end) {
    throw new Error(`Range start ${start} exceeds end ${end} at ${location}`);
  }
  throwIfOutOfBounds(start, min, max, location);
  throwIfOutOfBounds(end, min, max, location);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function expandedSegment(
  segment: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const location = `field "${fieldName}", segment "${segment}"`;

  if (segment === "*") {
    return expandedSteppedRange(min, max, 1, min, max, location);
  }

  // Stepped wildcard: */n
  const steppedWildcardMatch = /^\*\/(\d+)$/.exec(segment);
  if (steppedWildcardMatch !== null) {
    const step = integerFromToken(steppedWildcardMatch[1], location);
    return expandedSteppedRange(min, max, step, min, max, location);
  }

  // Range with optional step: a-b or a-b/c
  const rangeMatch = /^(\d+)-(\d+)(?:\/(\d+))?$/.exec(segment);
  if (rangeMatch !== null) {
    const start = integerFromToken(rangeMatch[1], location);
    const end   = integerFromToken(rangeMatch[2], location);
    const step  = rangeMatch[3] !== undefined
      ? integerFromToken(rangeMatch[3], location)
      : 1;
    return expandedSteppedRange(start, end, step, min, max, location);
  }

  // Single integer
  if (/^\d+$/.test(segment)) {
    const value = integerFromToken(segment, location);
    throwIfOutOfBounds(value, min, max, location);
    return [value];
  }

  throw new Error(`Unrecognized cron segment format at ${location}`);
}

function expandedField(token: string, field: CronField): number[] {
  if (token === undefined || token.trim().length === 0) {
    throw new Error(`Missing or empty field: "${field}"`);
  }

  const { min, max } = FIELD_BOUNDS[field];
  const segments = token.split(",");
  const accumulated = new Set<number>();

  for (const segment of segments) {
    const trimmedSegment = segment.trim();
    if (trimmedSegment.length === 0) {
      throw new Error(
        `Empty segment within field "${field}" token "${token}" — trailing or consecutive commas are not permitted`
      );
    }
    for (const value of expandedSegment(trimmedSegment, min, max, field)) {
      accumulated.add(value);
    }
  }

  if (accumulated.size === 0) {
    throw new Error(`Field "${field}" produced no values from token "${token}"`);
  }

  return Array.from(accumulated).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new Error(
      `parseCron requires a string argument, received ${typeof expression}`
    );
  }

  const trimmedExpression = expression.trim();
  if (trimmedExpression.length === 0) {
    throw new Error("Cron expression must not be empty or whitespace-only");
  }

  const tokens = trimmedExpression.split(/\s+/);
  if (tokens.length !== 5) {
    throw new Error(
      `Cron expression must contain exactly 5 whitespace-separated fields, received ${tokens.length}: "${expression}"`
    );
  }

  return {
    minute:     expandedField(tokens[0], "minute"),
    hour:       expandedField(tokens[1], "hour"),
    dayOfMonth: expandedField(tokens[2], "dayOfMonth"),
    month:      expandedField(tokens[3], "month"),
    dayOfWeek:  expandedField(tokens[4], "dayOfWeek"),
  };
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 6  },
] as const;

function parseDigits(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new RangeError(`Non-numeric token "${raw}" in ${context}`);
  }
  const n = Number(raw);
  if (!Number.isInteger(n)) {
    throw new RangeError(`Non-integer value "${raw}" in ${context}`);
  }
  return n;
}

function assertInRange(n: number, min: number, max: number, context: string): void {
  if (n < min || n > max) {
    throw new RangeError(`Value ${n} out of valid range [${min}, ${max}] in ${context}`);
  }
}

function expandStep(
  rangeMin: number,
  rangeMax: number,
  step: number,
  context: string,
): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step} in ${context}`);
  }
  const values: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += step) {
    values.push(v);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { name, min, max } = config;
  const ctx = `field "${name}"`;

  if (segment === "") {
    throw new SyntaxError(`Empty segment encountered in ${ctx}`);
  }

  // Step expressions: */n  |  a-b/n  |  a/n
  const slashIndex = segment.indexOf("/");
  if (slashIndex !== -1) {
    const leftPart  = segment.slice(0, slashIndex);
    const rightPart = segment.slice(slashIndex + 1);

    if (rightPart === "" || rightPart.includes("/")) {
      throw new SyntaxError(`Malformed step expression "${segment}" in ${ctx}`);
    }

    const step = parseDigits(rightPart, `step value of ${ctx}`);

    if (leftPart === "*") {
      return expandStep(min, max, step, ctx);
    }

    const dashIndex = leftPart.indexOf("-");
    if (dashIndex !== -1) {
      const [startStr, endStr] = [leftPart.slice(0, dashIndex), leftPart.slice(dashIndex + 1)];
      if (endStr.includes("-")) {
        throw new SyntaxError(`Malformed range in step expression "${segment}" in ${ctx}`);
      }
      const start = parseDigits(startStr, `range start of ${ctx}`);
      const end   = parseDigits(endStr,   `range end of ${ctx}`);
      assertInRange(start, min, max, ctx);
      assertInRange(end,   min, max, ctx);
      if (start > end) {
        throw new RangeError(`Range start ${start} exceeds end ${end} in ${ctx}`);
      }
      return expandStep(start, end, step, ctx);
    }

    // a/n — start at a, step through max
    const start = parseDigits(leftPart, `step base of ${ctx}`);
    assertInRange(start, min, max, ctx);
    return expandStep(start, max, step, ctx);
  }

  // Wildcard
  if (segment === "*") {
    const values: number[] = [];
    for (let v = min; v <= max; v++) values.push(v);
    return values;
  }

  // Range: a-b
  const dashIndex = segment.indexOf("-");
  if (dashIndex !== -1) {
    const startStr = segment.slice(0, dashIndex);
    const endStr   = segment.slice(dashIndex + 1);

    if (startStr === "" || endStr === "" || endStr.includes("-")) {
      throw new SyntaxError(`Malformed range "${segment}" in ${ctx}`);
    }

    const start = parseDigits(startStr, `range start of ${ctx}`);
    const end   = parseDigits(endStr,   `range end of ${ctx}`);
    assertInRange(start, min, max, ctx);
    assertInRange(end,   min, max, ctx);

    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in ${ctx}`);
    }

    const values: number[] = [];
    for (let v = start; v <= end; v++) values.push(v);
    return values;
  }

  // Plain number
  const value = parseDigits(segment, ctx);
  assertInRange(value, min, max, ctx);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (raw === undefined || raw === null || raw.trim() === "") {
    throw new SyntaxError(`Missing or empty value for field "${config.name}"`);
  }

  const parts = raw.split(",");
  const valueSet = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty item in comma-separated list for field "${config.name}"`);
    }
    for (const v of parseSegment(trimmed, config)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`,
    );
  }

  const [minuteRaw, hourRaw, dayOfMonthRaw, monthRaw, dayOfWeekRaw] = fields;

  return {
    minute:     parseField(minuteRaw,     FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,       FIELD_CONFIGS[1]),
    dayOfMonth: parseField(dayOfMonthRaw, FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,      FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dayOfWeekRaw,  FIELD_CONFIGS[4]),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: Record<string, Primitive> = {}
): Record<string, Primitive> {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }
  const keys = Object.keys(obj);
  if (keys.length === 0 && prefix) {
    result[prefix] = {} as unknown as Primitive;
    return result;
  }
  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;
    const newKey = prefix ? `${prefix}.${key}` : key;
    flattenObject(obj[key] as NestedObject, newKey, result);
  }
  return result;
}

const FIELD_RANGES = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 7 },
] as const;

type CronResult = Record<typeof FIELD_RANGES[number]["name"], number[]>;

const range = (min: number, max: number, step = 1): number[] =>
  Array.from({ length: Math.floor((max - min) / step) + 1 }, (_, i) => min + i * step);

const clamp = (v: number, min: number, max: number) => {
  if (v < min || v > max) throw new Error(`Value ${v} out of range [${min},${max}]`);
  return v;
};

const parseField = (field: string, min: number, max: number): number[] => {
  if (field === "*") return range(min, max);
  if (field.includes(",")) return [...new Set(field.split(",").flatMap(f => parseField(f, min, max)))].sort((a, b) => a - b);
  if (field.startsWith("*/")) return range(min, max, +field.slice(2) || (() => { throw new Error("Invalid step"); })());
  if (field.includes("/")) {
    const [r, s] = field.split("/");
    const [start, end] = r === "*" ? [min, max] : r.split("-").map(Number);
    return range(clamp(start, min, max), clamp(end ?? start, min, max), +s);
  }
  if (field.includes("-")) {
    const [lo, hi] = field.split("-").map(Number);
    return range(clamp(lo, min, max), clamp(hi, min, max));
  }
  return [clamp(+field, min, max)];
};

export default function parseCron(expr: string): CronResult {
  const parts = expr.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);
  return Object.fromEntries(
    FIELD_RANGES.map(({ name, min, max }, i) => [name, parseField(parts[i], min, max)])
  ) as CronResult;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, min: number, max: number): number[] {
  const full = range(min, max);

  if (expr === "*") return full;

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value: ${expr}`);
    return full.filter((v) => (v - min) % step === 0);
  }

  if (expr.includes(",")) {
    const parts = expr.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), min, max)) values.add(v);
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value: ${expr}`);
    let base: number[];
    if (rangePart === "*") {
      base = full;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${rangePart}`);
      if (start < min || end > max || start > end)
        throw new Error(`Range out of bounds: ${rangePart} (valid: ${min}-${max})`);
      base = range(start, end);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid range start: ${rangePart}`);
      if (start < min || start > max)
        throw new Error(`Value out of bounds: ${start} (valid: ${min}-${max})`);
      base = range(start, max);
    }
    return base.filter((v, i) => i % step === 0);
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${expr}`);
    if (start < min || end > max || start > end)
      throw new Error(`Range out of bounds: ${expr} (valid: ${min}-${max})`);
    return range(start, end);
  }

  const val = parseInt(expr, 10);
  if (isNaN(val)) throw new Error(`Invalid value: ${expr}`);
  if (val < min || val > max)
    throw new Error(`Value out of bounds: ${val} (valid: ${min}-${max})`);
  return [val];
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  const result = {} as CronFields;
  for (let i = 0; i < fields.length; i++) {
    const field = fields[i];
    const [min, max] = FIELD_RANGES[field];
    try {
      result[field] = parseField(exprs[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid cron field "${field}" (${exprs[i]}): ${(err as Error).message}`
      );
    }
  }

  return result;
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type NestedObject = { [key: string]: unknown };
type FlatObject = Record<string, Primitive | object>;

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  obj: NestedObject,
  prefix = "",
  ancestors = new WeakSet<object>()
): FlatObject {
  const result: FlatObject = {};

  if (ancestors.has(obj)) {
    // Circular reference detected — skip this branch entirely rather than
    // producing corrupt data or hanging indefinitely.
    return result;
  }

  ancestors.add(obj);

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      if (Object.keys(value).length === 0) {
        // Preserve empty objects as leaf values; recursing would silently
        // drop the key from the output.
        result[flatKey] = value;
      } else {
        const nested = flattenObject(value, flatKey, ancestors);
        Object.assign(result, nested);
      }
    } else {
      result[flatKey] = value as Primitive | object;
    }
  }

  // Remove from ancestors after processing so sibling branches sharing
  // the same object reference (diamond shapes) are handled correctly;
  // only true cycles (currently in the call stack) are blocked above.
  ancestors.delete(obj);

  return result;
}

export default flattenObject;

type PlainRecord = Record<string, unknown>;

const isPlainRecord = (value: unknown): value is PlainRecord => {
  if (value === null || typeof value !== "object" || Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value as object);
  return proto === Object.prototype || proto === null;
};

const accumulateFlattened = (
  obj: PlainRecord,
  prefix: string,
  accumulator: PlainRecord,
  visited: WeakSet<object>
): void => {
  visited.add(obj);

  const ownKeys = Object.keys(obj);

  if (ownKeys.length === 0) {
    if (prefix.length > 0) {
      accumulator[prefix] = {};
    }
    visited.delete(obj);
    return;
  }

  for (const key of ownKeys) {
    const value = obj[key];
    const composedKey = prefix.length === 0 ? key : `${prefix}.${key}`;

    if (isPlainRecord(value) && !visited.has(value)) {
      accumulateFlattened(value, composedKey, accumulator, visited);
    } else {
      accumulator[composedKey] = value;
    }
  }

  visited.delete(obj);
};

export default function flattenObject(obj: PlainRecord): PlainRecord {
  if (!isPlainRecord(obj)) {
    throw new TypeError(
      `flattenObject requires a plain object; received ${
        obj === null ? "null" : Array.isArray(obj) ? "Array" : typeof obj
      }`
    );
  }

  const accumulator: PlainRecord = {};
  const visited = new WeakSet<object>();
  accumulateFlattened(obj, "", accumulator, visited);
  return accumulator;
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(field: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of field.split(",")) {
    if (part === "*") {
      for (let i = min; i <= max; i++) results.add(i);
    } else if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${part}`);
      for (let i = min; i <= max; i += step) results.add(i);
    } else if (part.includes("/")) {
      const [rangePart, stepPart] = part.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${part}`);
      const [rangeStart, rangeEnd] = rangePart.includes("-")
        ? rangePart.split("-").map(Number)
        : [parseInt(rangePart, 10), max];
      if (isNaN(rangeStart) || isNaN(rangeEnd)) throw new Error(`Invalid range: ${part}`);
      if (rangeStart < min || rangeEnd > max) throw new Error(`Out of range: ${part}`);
      for (let i = rangeStart; i <= rangeEnd; i += step) results.add(i);
    } else if (part.includes("-")) {
      const [start, end] = part.split("-").map(Number);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${part}`);
      if (start < min || end > max || start > end) throw new Error(`Out of range: ${part}`);
      for (let i = start; i <= end; i++) results.add(i);
    } else {
      const val = parseInt(part, 10);
      if (isNaN(val)) throw new Error(`Invalid value: ${part}`);
      if (val < min || val > max) throw new Error(`Value ${val} out of range [${min}, ${max}]`);
      results.add(val);
    }
  }

  return Array.from(results).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteField, hourField, domField, monthField, dowField,
  ].map((field, i) => {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    return parseField(field, min, max);
  });

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

type FlatValue = unknown;
type FlatObject = Record<string, FlatValue>;

function isExpandable(value: unknown): value is Record<string | number, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  // Only recurse into plain objects and arrays — treat Date, RegExp, Map, Set, etc. as leaf values
  return proto === Object.prototype || proto === null || Array.isArray(value);
}

function flattenInto(
  obj: Record<string | number, unknown>,
  prefix: string,
  result: FlatObject,
  seen: WeakSet<object>
): void {
  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected${prefix ? ` at key "${prefix}"` : ""}`
    );
  }

  seen.add(obj);

  const keys = Object.keys(obj);

  for (const key of keys) {
    const value = obj[key];
    // Guard against inherited properties sneaking in via unusual prototypes
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const flatKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isExpandable(value)) {
      const nested = value as Record<string | number, unknown>;
      const nestedKeys = Object.keys(nested);

      if (nestedKeys.length === 0) {
        // Empty object/array — preserve as-is at this key rather than silently dropping it
        result[flatKey] = value;
      } else {
        flattenInto(nested, flatKey, result, seen);
      }
    } else {
      result[flatKey] = value;
    }
  }

  // Remove from seen after processing so the same reference can appear
  // in a separate, non-circular branch without a false positive
  seen.delete(obj);
}

export default function flattenObject(obj: Record<string, unknown>): FlatObject {
  if (obj === null || typeof obj !== "object") {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${obj === null ? "null" : typeof obj}`
    );
  }

  const result: FlatObject = {};
  flattenInto(obj as Record<string | number, unknown>, "", result, new WeakSet());
  return result;
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseField(expr: string, min: number, max: number): number[] {
  if (expr === "*") {
    return range(min, max);
  }

  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in expression: ${expr}`);
    }
    return range(min, max).filter((v) => (v - min) % step === 0);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in expression: ${expr}`);
    }
    const [rangeStart, rangeEnd] = rangePart.includes("-")
      ? rangePart.split("-").map(Number)
      : [parseInt(rangePart, 10), max];
    if (isNaN(rangeStart) || isNaN(rangeEnd)) {
      throw new Error(`Invalid range in expression: ${expr}`);
    }
    validate(rangeStart, min, max, expr);
    validate(rangeEnd, min, max, expr);
    return range(rangeStart, rangeEnd).filter((v) => (v - rangeStart) % step === 0);
  }

  if (expr.includes("-")) {
    const [start, end] = expr.split("-").map(Number);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range in expression: ${expr}`);
    }
    if (start > end) {
      throw new Error(`Range start ${start} is greater than end ${end} in expression: ${expr}`);
    }
    validate(start, min, max, expr);
    validate(end, min, max, expr);
    return range(start, end);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value in expression: ${expr}`);
  }
  validate(value, min, max, expr);
  return [value];
}

function validate(value: number, min: number, max: number, expr: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of range [${min}, ${max}] in expression: ${expr}`
    );
  }
}

export function parseCron(cronExpression: string): CronResult {
  const fields = cronExpression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${fields.length}: "${cronExpression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return keys.reduce((result, key, i) => {
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(exprs[i], min, max);
    return result;
  }, {} as CronResult);
}

export default parseCron;

type NestedObject = { [key: string]: unknown };
type FlatRecord = Record<string, unknown>;

const isPlainObjectByProto = (value: unknown): boolean => {
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
};

const isTraversableNode = (
  value: unknown,
  ancestorSet: WeakSet<object>
): value is NestedObject =>
  value !== null &&
  typeof value === "object" &&
  !Array.isArray(value) &&
  isPlainObjectByProto(value) &&
  !ancestorSet.has(value as object);

const accumulateFlatEntries = (
  node: NestedObject,
  prefix: string,
  ancestors: WeakSet<object>,
  accumulator: FlatRecord
): void => {
  ancestors.add(node);

  const entries = Object.entries(node);

  if (entries.length === 0) {
    if (prefix.length > 0) {
      accumulator[prefix] = node;
    }
    ancestors.delete(node);
    return;
  }

  for (const [key, value] of entries) {
    const dotKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isTraversableNode(value, ancestors)) {
      accumulateFlatEntries(value, dotKey, ancestors, accumulator);
    } else {
      accumulator[dotKey] = value;
    }
  }

  ancestors.delete(node);
};

const flattenObject = (input: NestedObject): FlatRecord => {
  const accumulator: FlatRecord = {};

  if (
    input === null ||
    typeof input !== "object" ||
    Array.isArray(input)
  ) {
    return accumulator;
  }

  accumulateFlatEntries(input, "", new WeakSet<object>(), accumulator);
  return accumulator;
};

export default flattenObject;

type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: unknown };

function flatten(obj: NestedObject, prefix: string, result: FlatObject): void {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flatten(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value;
    }
  }
}

export default function flattenObject(obj: NestedObject): FlatObject {
  const result: FlatObject = {};
  flatten(obj, "", result);
  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  obj: PlainObject,
  prefix = "",
  seen = new WeakSet<object>()
): PlainObject {
  if (!isPlainObject(obj)) {
    throw new TypeError(`Expected a plain object, got ${obj === null ? "null" : typeof obj}`);
  }

  if (seen.has(obj)) {
    throw new Error(`Circular reference detected at key "${prefix}"`);
  }

  seen.add(obj);

  const result: PlainObject = {};

  for (const key of Object.keys(obj)) {
    if (key === "") {
      // Empty-string keys would silently corrupt dot-notation paths
      throw new Error(`Empty string key encountered at path "${prefix}"`);
    }

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (isPlainObject(value)) {
      if (Object.keys(value).length === 0) {
        // Preserve empty objects as leaf values to avoid silent data loss
        result[fullKey] = value;
      } else {
        const nested = flattenObject(value, fullKey, seen);
        Object.assign(result, nested);
      }
    } else {
      result[fullKey] = value;
    }
  }

  // Remove after processing so the same object reference can appear
  // at sibling paths without false circular-reference positives
  seen.delete(obj);

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Handle comma-separated lists by recursively parsing each part
  if (expression.includes(",")) {
    const parts = expression.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const val of parseField(part.trim(), field)) {
        values.add(val);
      }
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  // Handle wildcard
  if (expression === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Handle step values (*/n or range/n)
  if (expression.includes("/")) {
    const [rangePart, stepStr] = expression.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in "${expression}" for field "${field}"`);
    }

    let rangeValues: number[];

    if (rangePart === "*") {
      rangeValues = Array.from({ length: max - min + 1 }, (_, i) => min + i);
    } else if (rangePart.includes("-")) {
      rangeValues = parseRange(rangePart, min, max, field);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) {
        throw new Error(`Invalid start value in "${expression}" for field "${field}"`);
      }
      validateValue(start, min, max, field);
      rangeValues = Array.from({ length: max - start + 1 }, (_, i) => start + i);
    }

    return rangeValues.filter((_, i) => i % step === 0);
  }

  // Handle range (e.g., "1-5")
  if (expression.includes("-")) {
    return parseRange(expression, min, max, field);
  }

  // Handle single number
  const value = parseInt(expression, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${expression}" for field "${field}"`);
  }
  validateValue(value, min, max, field);

  // Normalize day of week: 7 is treated as Sunday (0)
  if (field === "dayOfWeek" && value === 7) {
    return [0];
  }

  return [value];
}

function parseRange(
  expression: string,
  min: number,
  max: number,
  field: CronField
): number[] {
  const parts = expression.split("-");
  if (parts.length !== 2) {
    throw new Error(`Invalid range "${expression}" for field "${field}"`);
  }

  const start = parseInt(parts[0], 10);
  const end = parseInt(parts[1], 10);

  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Invalid range "${expression}" for field "${field}"`);
  }

  validateValue(start, min, max, field);
  validateValue(end, min, max, field);

  if (start > end) {
    throw new Error(
      `Range start (${start}) is greater than end (${end}) in "${expression}" for field "${field}"`
    );
  }

  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function validateValue(value: number, min: number, max: number, field: CronField): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  const result: CronResult = {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };

  // Deduplicate and sort all fields (dayOfWeek may have 7 normalized to 0)
  for (const key of Object.keys(result) as CronField[]) {
    result[key] = Array.from(new Set(result[key])).sort((a, b) => a - b);
  }

  return result;
}

export default parseCron;

type CronResult = Record<"minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek", number[]>;

const FIELDS = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max:  7 },
] as const;

const seq = (a: number, b: number) => Array.from({ length: b - a + 1 }, (_, i) => a + i);

function parseField(expr: string, min: number, max: number): number[] {
  if (expr.includes(","))
    return [...new Set(expr.split(",").flatMap(p => parseField(p, min, max)))].sort((a, b) => a - b);

  if (expr === "*") return seq(min, max);

  if (expr.startsWith("*/")) {
    const step = Number(expr.slice(2));
    if (!Number.isInteger(step) || step <= 0) throw new Error(`Invalid step: ${expr}`);
    return seq(min, max).filter(n => (n - min) % step === 0);
  }

  if (expr.includes("-")) {
    const [a, b] = expr.split("-").map(Number);
    if (!Number.isInteger(a) || !Number.isInteger(b) || a > b || a < min || b > max)
      throw new Error(`Invalid range: ${expr} (valid: ${min}-${max})`);
    return seq(a, b);
  }

  const n = Number(expr);
  if (!Number.isInteger(n) || n < min || n > max)
    throw new Error(`Invalid value: ${expr} (valid: ${min}-${max})`);
  return [n];
}

export default function parseCron(cron: string): CronResult {
  const parts = cron.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);
  return Object.fromEntries(
    FIELDS.map(({ name, min, max }, i) => [name, parseField(parts[i], min, max)])
  ) as CronResult;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

type CronExpression = {
  readonly [K in CronField]: readonly number[];
};

type FieldBounds = {
  readonly field: CronField;
  readonly min: number;
  readonly max: number;
};

const FIELD_BOUNDS: readonly FieldBounds[] = [
  { field: "minute",     min: 0,  max: 59 },
  { field: "hour",       min: 0,  max: 23 },
  { field: "dayOfMonth", min: 1,  max: 31 },
  { field: "month",      min: 1,  max: 12 },
  { field: "dayOfWeek",  min: 0,  max: 6  },
] as const;

const toDigits = (raw: string, field: CronField): number => {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Non-integer token "${raw}" in field "${field}"`);
  }
  return parseInt(raw, 10);
};

const clampedValue = (n: number, min: number, max: number, field: CronField): number => {
  if (n < min || n > max) {
    throw new Error(
      `Value ${n} is outside allowed range [${min}, ${max}] for field "${field}"`
    );
  }
  return n;
};

const expandedRange = (
  from: number,
  to: number,
  step: number,
  field: CronField
): number[] => {
  if (step <= 0) {
    throw new Error(`Step must be ≥ 1, got ${step} in field "${field}"`);
  }
  if (from > to) {
    throw new Error(
      `Range start ${from} exceeds end ${to} in field "${field}"`
    );
  }
  const result: number[] = [];
  for (let i = from; i <= to; i += step) {
    result.push(i);
  }
  return result;
};

const tokenToValues = (
  token: string,
  min: number,
  max: number,
  field: CronField
): number[] => {
  if (token === "*") {
    return expandedRange(min, max, 1, field);
  }

  const wildcardStep = token.match(/^\*\/(\d+)$/);
  if (wildcardStep !== null) {
    const step = toDigits(wildcardStep[1], field);
    if (step === 0) {
      throw new Error(`Step of 0 not permitted in field "${field}"`);
    }
    return expandedRange(min, max, step, field);
  }

  const rangeWithStep = token.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeWithStep !== null) {
    const from = clampedValue(toDigits(rangeWithStep[1], field), min, max, field);
    const to   = clampedValue(toDigits(rangeWithStep[2], field), min, max, field);
    const step = rangeWithStep[3] !== undefined
      ? toDigits(rangeWithStep[3], field)
      : 1;
    if (step === 0) {
      throw new Error(`Step of 0 not permitted in field "${field}"`);
    }
    return expandedRange(from, to, step, field);
  }

  const plainNumber = token.match(/^(\d+)$/);
  if (plainNumber !== null) {
    const n = toDigits(plainNumber[1], field);
    return [clampedValue(n, min, max, field)];
  }

  throw new Error(`Unrecognized token "${token}" in field "${field}"`);
};

const fieldToValues = (
  segment: string,
  min: number,
  max: number,
  field: CronField
): number[] => {
  const tokens = segment.split(",");

  if (tokens.length === 0) {
    throw new Error(`Empty expression for field "${field}"`);
  }

  const expanded = tokens.flatMap((token) => {
    const trimmed = token.trim();
    if (trimmed.length === 0) {
      throw new Error(`Empty token in field "${field}"`);
    }
    return tokenToValues(trimmed, min, max, field);
  });

  return [...new Set(expanded)].sort((a, b) => a - b);
};

const parseCron = (expression: string): CronExpression => {
  if (typeof expression !== "string") {
    throw new Error(
      `parseCron requires a string argument, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error("Cron expression must not be empty");
  }

  const segments = trimmed.split(/\s+/);
  if (segments.length !== 5) {
    throw new Error(
      `Cron expression requires exactly 5 fields, got ${segments.length}`
    );
  }

  return FIELD_BOUNDS.reduce<CronExpression>(
    (accumulator, { field, min, max }, index) => ({
      ...accumulator,
      [field]: fieldToValues(segments[index], min, max, field),
    }),
    {} as CronExpression
  );
};

export default parseCron;

type FlatRecord = Record<string, unknown>;

const recursable = (value: unknown): value is Record<string | number, unknown> => {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null || Array.isArray(value);
};

const keysOf = (value: Record<string | number, unknown>): string[] =>
  Array.isArray(value)
    ? Array.from({ length: value.length }, (_, i) => String(i))
    : Object.keys(value);

const flattenObjectInner = (
  input: Record<string | number, unknown>,
  prefix: string,
  ancestors: WeakSet<object>
): FlatRecord => {
  const output: FlatRecord = {};
  const ownKeys = keysOf(input);

  if (ownKeys.length === 0) {
    if (prefix.length > 0) output[prefix] = input;
    return output;
  }

  ancestors.add(input);

  for (const key of ownKeys) {
    const dotKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = input[key];

    if (recursable(value)) {
      if (ancestors.has(value)) {
        output[dotKey] = "[Circular]";
      } else {
        Object.assign(output, flattenObjectInner(value, dotKey, ancestors));
      }
    } else {
      output[dotKey] = value;
    }
  }

  ancestors.delete(input);

  return output;
};

const flattenObject = (input: Record<string, unknown>): FlatRecord =>
  flattenObjectInner(input, "", new WeakSet<object>());

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map || value instanceof Set) return false;
  return Object.getPrototypeOf(value) === Object.prototype ||
    Object.getPrototypeOf(value) === null;
}

function flattenObject(
  obj: PlainObject,
  prefix = "",
  ancestors = new WeakSet<object>()
): Record<string, unknown> {
  if (!isPlainObject(obj)) {
    return prefix !== "" ? { [prefix]: obj } : {};
  }

  if (ancestors.has(obj)) {
    return prefix !== "" ? { [prefix]: "[Circular]" } : {};
  }

  ancestors.add(obj);
  const result: Record<string, unknown> = {};

  for (const key of Object.keys(obj)) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value = obj[key];
    const fullKey = prefix !== "" ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      if (Object.keys(value as PlainObject).length === 0) {
        // Empty object: preserve as a leaf so the key isn't silently dropped
        result[fullKey] = value;
      } else {
        const nested = flattenObject(value as PlainObject, fullKey, ancestors);
        Object.assign(result, nested);
      }
    } else {
      result[fullKey] = value;
    }
  }

  // Remove from ancestors after processing so sibling paths to the same
  // object are not falsely flagged as circular references
  ancestors.delete(obj);

  return result;
}

export default flattenObject;

type CronFieldName = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  readonly minute: number[];
  readonly hour: number[];
  readonly dayOfMonth: number[];
  readonly month: number[];
  readonly dayOfWeek: number[];
}

interface FieldBounds {
  readonly min: number;
  readonly max: number;
}

const FIELD_BOUNDS: Record<CronFieldName, FieldBounds> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: CronFieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function integerFromString(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(
      `Non-integer token "${trimmed}" in ${context} — only unsigned integers are accepted here`
    );
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isFinite(n) || !Number.isInteger(n)) {
    throw new Error(
      `Could not produce a finite integer from "${trimmed}" in ${context}`
    );
  }
  return n;
}

function withinBounds(value: number, bounds: FieldBounds): boolean {
  return value >= bounds.min && value <= bounds.max;
}

function linearSequence(
  start: number,
  end: number,
  step: number,
  context: string
): number[] {
  if (step <= 0) {
    throw new Error(
      `Step value must be a positive integer in ${context}, got ${step}`
    );
  }
  if (start > end) {
    throw new Error(
      `Range start (${start}) exceeds range end (${end}) in ${context}`
    );
  }
  const result: number[] = [];
  for (let cursor = start; cursor <= end; cursor += step) {
    result.push(cursor);
  }
  return result;
}

function expandAtom(
  token: string,
  bounds: FieldBounds,
  fieldName: CronFieldName
): number[] {
  const trimmed = token.trim();

  if (trimmed === "") {
    throw new Error(
      `Empty atom encountered in field "${fieldName}" — each comma-separated segment must be non-empty`
    );
  }

  // Wildcard ("*") or step over full range ("*/N")
  if (trimmed[0] === "*") {
    if (trimmed === "*") {
      return linearSequence(bounds.min, bounds.max, 1, `field "${fieldName}"`);
    }
    if (trimmed.startsWith("*/")) {
      const stepRaw = trimmed.slice(2);
      if (stepRaw === "") {
        throw new Error(
          `Missing step value after "*/" in field "${fieldName}"`
        );
      }
      const step = integerFromString(stepRaw, `step of field "${fieldName}"`);
      return linearSequence(
        bounds.min,
        bounds.max,
        step,
        `field "${fieldName}"`
      );
    }
    throw new Error(
      `Unrecognised wildcard expression "${trimmed}" in field "${fieldName}" — expected "*" or "*/N"`
    );
  }

  // Range ("N-M") — must be checked before single-number to catch e.g. "1-5"
  if (trimmed.includes("-")) {
    const dashParts = trimmed.split("-");
    if (dashParts.length !== 2) {
      throw new Error(
        `Range expression "${trimmed}" in field "${fieldName}" must have exactly one dash`
      );
    }
    const rangeStart = integerFromString(
      dashParts[0],
      `range start of field "${fieldName}"`
    );
    const rangeEnd = integerFromString(
      dashParts[1],
      `range end of field "${fieldName}"`
    );
    if (!withinBounds(rangeStart, bounds)) {
      throw new Error(
        `Range start ${rangeStart} is outside the allowed bounds [${bounds.min}, ${bounds.max}] for field "${fieldName}"`
      );
    }
    if (!withinBounds(rangeEnd, bounds)) {
      throw new Error(
        `Range end ${rangeEnd} is outside the allowed bounds [${bounds.min}, ${bounds.max}] for field "${fieldName}"`
      );
    }
    return linearSequence(
      rangeStart,
      rangeEnd,
      1,
      `range in field "${fieldName}"`
    );
  }

  // Single numeric value
  const n = integerFromString(trimmed, `value in field "${fieldName}"`);
  if (!withinBounds(n, bounds)) {
    throw new Error(
      `Value ${n} is outside the allowed bounds [${bounds.min}, ${bounds.max}] for field "${fieldName}"`
    );
  }
  return [n];
}

function expandField(
  expression: string,
  bounds: FieldBounds,
  fieldName: CronFieldName
): number[] {
  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error(
      `Field "${fieldName}" must not be empty — received an empty string`
    );
  }

  const segments = trimmed.split(",");

  if (segments.length === 0) {
    throw new Error(
      `Field "${fieldName}" produced zero segments after splitting — this should be impossible`
    );
  }

  const accumulated = new Set<number>();

  for (const segment of segments) {
    const values = expandAtom(segment, bounds, fieldName);
    for (const v of values) {
      accumulated.add(v);
    }
  }

  return Array.from(accumulated).sort((a, b) => a - b);
}

function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new Error(
      `parseCron requires a string argument, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error(
      "Cron expression must not be empty or whitespace-only"
    );
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must contain exactly 5 whitespace-separated fields, found ${fields.length} in: "${trimmed}"`
    );
  }

  const fieldMap: Record<CronFieldName, string> = {
    minute:     fields[0],
    hour:       fields[1],
    dayOfMonth: fields[2],
    month:      fields[3],
    dayOfWeek:  fields[4],
  };

  const result = {} as Record<CronFieldName, number[]>;

  for (const fieldName of FIELD_ORDER) {
    result[fieldName] = expandField(
      fieldMap[fieldName],
      FIELD_BOUNDS[fieldName],
      fieldName
    );
  }

  return result as CronExpression;
}

export default parseCron;

type PlainObject = { [key: string]: unknown };

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

export default function flattenObject(
  obj: PlainObject,
  prefix = "",
  seen = new WeakSet<object>()
): Record<string, unknown> {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  if (seen.has(obj)) {
    throw new Error(
      `Circular reference detected${prefix ? ` at key "${prefix}"` : ""}`
    );
  }

  seen.add(obj);

  const result: Record<string, unknown> = {};

  for (const key of Object.keys(obj)) {
    // Guard against keys that could corrupt dot-notation paths
    if (key === "") {
      throw new Error(
        `Empty string key found${prefix ? ` under "${prefix}"` : ""} — dot-notation path would be ambiguous`
      );
    }

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (isPlainObject(value)) {
      // Empty plain objects produce no leaf keys — they vanish.
      // This is information-lossy but preserves the invariant that every
      // output value is a concrete leaf. Callers who need empty-object
      // sentinel values should pre-process their input.
      const nested = flattenObject(value, fullKey, seen);
      Object.assign(result, nested);
    } else {
      // Arrays, Dates, RegExps, primitives, null, undefined → leaf values.
      result[fullKey] = value;
    }
  }

  // Remove from `seen` after processing so the same object reference can
  // legally appear at a different, non-circular path (DAG structure).
  seen.delete(obj);

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  // Treat built-in object types (Date, RegExp, Map, Set, etc.) as leaf values
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  obj: PlainObject,
  prefix = "",
  result: PlainObject = {},
  visited = new WeakSet<object>()
): PlainObject {
  if (obj === null || obj === undefined) return result;

  if (visited.has(obj)) {
    // Circular reference detected — treat as leaf to avoid infinite recursion
    if (prefix) result[prefix] = "[Circular]";
    return result;
  }

  visited.add(obj);

  const keys = Object.keys(obj);

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value = obj[key];
    const newKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const childKeys = Object.keys(value);
      if (childKeys.length === 0) {
        // Empty plain object — preserve as leaf so the key is not silently lost
        result[newKey] = value;
      } else {
        flattenObject(value, newKey, result, visited);
      }
    } else {
      result[newKey] = value;
    }
  }

  visited.delete(obj);

  return result;
}

export default flattenObject;

type Scalar = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Scalar | unknown[] };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flatten(
  obj: NestedObject,
  prefix: string,
  seen: WeakSet<object>,
  result: Record<string, unknown>
): void {
  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected${prefix ? ` at key "${prefix}"` : ""}`
    );
  }

  seen.add(obj);

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const compositeKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const childKeys = Object.keys(value);
      if (childKeys.length === 0) {
        // Preserve empty objects as leaf values rather than silently dropping the key
        result[compositeKey] = value;
      } else {
        flatten(value, compositeKey, seen, result);
      }
    } else {
      // Arrays, primitives, Dates, RegExps, class instances — treat as leaves
      result[compositeKey] = value;
    }
  }

  // Remove after processing so the same reference can appear at a different path
  seen.delete(obj);
}

export default function flattenObject(
  obj: NestedObject
): Record<string, unknown> {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: Record<string, unknown> = {};
  flatten(obj, "", new WeakSet(), result);
  return result;
}

type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: unknown };

function flattenObject(obj: NestedObject, prefix = ""): FlatObject {
  const result: FlatObject = {};

  for (const [key, value] of Object.entries(obj)) {
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
      Object.assign(result, flattenObject(value as NestedObject, flatKey));
    } else {
      result[flatKey] = value;
    }
  }

  return result;
}

export default flattenObject;
